function go(p){document.querySelectorAll('.ni').forEach(el=>el.classList.toggle('active',el.dataset.p===p));document.getElementById('tt').textContent=titles[p]||p;cSB();({dash:pgDash,leads:pgLeads,karte:pgKarte,auf:pgAufgaben,kunden:pgKunden,proj:pgProj,termine:pgTermine,angebote:pgAngebote,mit:pgMit,std:pgStd,mat:pgMat,rech:pgRech,einst:pgEinst})[p]?.();}
