async function loadSettings(){try{const{data}=await sb.from('einstellungen').select('*').eq('user_id',me.id).single();if(data)settings={...settings,...data};}catch(e){}}
async function saveSettings(){const o={user_id:me.id,firma:document.getElementById('s-firma').value,adresse:document.getElementById('s-adr').value,telefon:document.getElementById('s-tel').value,email:document.getElementById('s-em').value,mwst:parseFloat(document.getElementById('s-mwst').value)||19,zahlungsziel:parseInt(document.getElementById('s-ziel').value)||14,iban:document.getElementById('s-iban').value,bank:document.getElementById('s-bank').value,ustid:document.getElementById('s-ustid').value,steuernr:document.getElementById('s-steuernr').value};const{error}=await sb.from('einstellungen').upsert(o,{onConflict:'user_id'});if(error){alert('Fehler: '+error.message);return;}settings={...settings,...o};alert('Gespeichert!');pgEinst();}
async function pgDash(){ld();try{const[r1,r2,r3,r4]=await Promise.all([sb.from('projekte').select('*'),sb.from('kunden').select('*'),sb.from('termine').select('*'),sb.from('rechnungen').select('betrag,status')]);const proj=r1.data||[],ku=r2.data||[],t=r3.data||[],r=r4.data||[];const offen=r.filter(x=>x.status==='offen').reduce((s,x)=>s+(parseFloat(x.betrag)||0),0);const bezahlt=r.filter(x=>x.status==='bezahlt').reduce((s,x)=>s+(parseFloat(x.betrag)||0),0);const hT=t.filter(x=>x.datum===heute());const wochentage=['Sonntag','Montag','Dienstag','Mittwoch','Donnerstag','Freitag','Samstag'];const monate=['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];const now=new Date();const datumStr=`${wochentage[now.getDay()]}, ${now.getDate()}. ${monate[now.getMonth()]} ${now.getFullYear()}`;sC(`<div style="margin-bottom:24px"><div style="font-size:12px;font-weight:500;color:var(--text-ter);margin-bottom:4px">${datumStr}</div><div style="font-size:24px;font-weight:800;color:var(--text);letter-spacing:-0.5px">Guten Tag</div></div><div class="sts"><div class="st" onclick="go('rech')" style="cursor:pointer"><div class="si">💶</div><div class="sv">${fmtEur(offen)}</div><div class="sl">Ausstehend</div></div><div class="st" onclick="go('rech')" style="cursor:pointer"><div class="si">✅</div><div class="sv" style="color:var(--green)">${fmtEur(bezahlt)}</div><div class="sl">Bezahlt</div></div><div class="st" onclick="go('proj')" style="cursor:pointer"><div class="si">🏗️</div><div class="sv">${proj.filter(p=>p.status==='Aktiv'||!p.status).length}</div><div class="sl">Aktive Projekte</div></div><div class="st" onclick="go('termine')" style="cursor:pointer"><div class="si">📅</div><div class="sv">${hT.length}</div><div class="sl">Heute Termine</div></div></div><div class="section-hdr"><span class="section-hdr-title">Schnellzugriff</span></div><div class="quick-actions"><button class="quick-btn" onclick="go('leads')"><div class="quick-btn-icon">🎯</div><div class="quick-btn-label">Akquise</div></button><button class="quick-btn" onclick="go('rech')"><div class="quick-btn-icon">💶</div><div class="quick-btn-label">Rechnung erstellen</div></button><button class="quick-btn" onclick="go('angebote')"><div class="quick-btn-icon">📄</div><div class="quick-btn-label">Angebot erstellen</div></button></div>${hT.length?`<div class="section-hdr"><span class="section-hdr-title">Heute</span></div><div class="tc" style="margin-bottom:16px">${hT.map(t=>`<div style="display:flex;align-items:center;gap:12px;padding:12px 16px;border-bottom:1px solid var(--border-l)"><div style="width:6px;height:6px;border-radius:50%;background:var(--p);flex-shrink:0"></div><div style="flex:1"><div style="font-size:13px;font-weight:500;color:var(--text)">${t.titel||'-'}</div></div><div style="font-size:12px;color:var(--text-ter)">${t.uhrzeit||''}</div></div>`).join('')}</div>`:''}<div class="section-hdr"><span class="section-hdr-title">Aktive Projekte</span><button class="section-hdr-link" onclick="go('proj')">Alle anzeigen</button></div>${!proj.length?'<div class="em"><div class="em-t">Noch keine Projekte</div></div>':`<div class="gr">${proj.filter(p=>p.status==='Aktiv'||!p.status).slice(0,4).map(p=>`<div class="ca" onclick="pgProjDetail('${p.id}')"><div style="display:flex;justify-content:space-between;align-items:flex-start"><div><div class="ca-t">${p.name||'-'}</div><div class="ca-s">${p.adresse||p.kunde||'-'}</div></div><span class="bd bd-b">${p.status||'Aktiv'}</span></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">Fehler: ${e.message}</div></div>`);}}
async function pgKunden(){ld();try{const{data}=await sb.from('kunden').select('*').order('created_at',{ascending:false});sC(`<div class="ph"><div><div class="pt">Kunden</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick="mKunde()">+ Neuer Kunde</button></div>${!(data&&data.length)?'<div class="em"><div class="em-t">Noch keine Kunden</div></div>':`<div class="gr">${data.map(k=>`<div class="ca" onclick='mKunde(${JSON.stringify(k).replace(/'/g,"&#39;")})' ><div style="display:flex;align-items:center;gap:12px"><div style="width:36px;height:36px;background:var(--p-light);border-radius:9px;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:var(--p);flex-shrink:0">${(k.name||'?')[0].toUpperCase()}</div><div style="flex:1;min-width:0"><div class="ca-t">${k.name||'-'}</div><div class="ca-s">${k.telefon||k.email||'-'}</div></div></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mKunde(k={}){oM(`${modalHeader(k.id?'Kunde bearbeiten':'Neuer Kunde')}<div class="fg"><label>NAME *</label><input id="f-n" value="${k.name||''}" placeholder="Frank Müller"></div><div class="fr"><div class="fg"><label>TELEFON</label><input id="f-tel" value="${k.telefon||''}" placeholder="+49 176 ..."></div><div class="fg"><label>E-MAIL</label><input id="f-em" value="${k.email||''}" placeholder="info@..."></div></div><div class="fg"><label>ADRESSE</label><input id="f-adr" value="${k.adresse||''}" placeholder="Musterstr. 1, Berlin"></div><div class="fg"><label>NOTIZ</label><textarea id="f-not" rows="2">${k.notiz||''}</textarea></div><div class="ma">${k.id?`<button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delKunde('${k.id}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveKunde('${k.id||''}')">Speichern</button></div>`);}
async function saveKunde(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Bitte Name eingeben!');return;}const o={name:n,telefon:document.getElementById('f-tel').value,email:document.getElementById('f-em').value,adresse:document.getElementById('f-adr').value,notiz:document.getElementById('f-not').value,user_id:me.id};const{error}=id?await sb.from('kunden').update(o).eq('id',id):await sb.from('kunden').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgKunden();}
async function delKunde(id){if(!confirm('Kunde wirklich löschen?'))return;await sb.from('kunden').delete().eq('id',id);cM();pgKunden();}
async function pgProj(){ld();try{const{data}=await sb.from('projekte').select('*').order('created_at',{ascending:false});sC(`<div class="ph"><div><div class="pt">Projekte</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick="mProj()">+ Neues Projekt</button></div>${!(data&&data.length)?'<div class="em"><div class="em-t">Noch keine Projekte</div></div>':`<div class="gr">${data.map(p=>`<div class="ca" onclick="pgProjDetail('${p.id}')"><div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px"><div><div class="ca-t">${p.name||'-'}</div><div class="ca-s">${p.kunde||p.kunde_name||'-'}</div></div><span class="bd ${p.status==='Abgeschlossen'?'bd-g':p.status==='Pausiert'?'bd-gr':'bd-b'}">${p.status||'Aktiv'}</span></div>${p.adresse?`<div style="font-size:12px;color:var(--text-ter)">📍 ${p.adresse}</div>`:''}</div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
async function mProj(){const{data:ku}=await sb.from('kunden').select('id,name');oM(`${modalHeader('Neues Projekt')}<div class="fg"><label>PROJEKTNAME *</label><input id="f-n" placeholder="z.B. Baustelle Berlin"></div><div class="fg"><label>KUNDE</label><select id="f-ku"><option value="">- Kein Kunde -</option>${(ku||[]).map(k=>`<option value="${k.id}" data-n="${k.name}">${k.name}</option>`).join('')}</select></div><div class="fg"><label>ADRESSE</label><input id="f-adr" placeholder="Musterstraße 1, Berlin"></div><div class="fg"><label>STATUS</label><select id="f-st"><option value="Aktiv">Aktiv</option><option value="Pausiert">Pausiert</option><option value="Abgeschlossen">Abgeschlossen</option></select></div><div class="fg"><label>BESCHREIBUNG</label><textarea id="f-desc" rows="3"></textarea></div><div class="fr"><div class="fg"><label>START</label><input id="f-start" type="date" value="${heute()}"></div><div class="fg"><label>ENDE</label><input id="f-end" type="date"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveProj()">Speichern</button></div>`);}
async function saveProj(){const n=document.getElementById('f-n').value.trim();if(!n){alert('Projektname fehlt!');return;}const s=document.getElementById('f-ku');const ki=s.value||null,kn=ki?s.options[s.selectedIndex].dataset.n:'';const{error}=await sb.from('projekte').insert({name:n,kunden_id:ki,kunde_name:kn,kunde:kn,adresse:document.getElementById('f-adr').value,beschreibung:document.getElementById('f-desc').value,status:document.getElementById('f-st').value,datum_start:document.getElementById('f-start').value||null,datum_end:document.getElementById('f-end').value||null,autor_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgProj();}
async function delProj(id){if(!confirm('Projekt wirklich löschen?'))return;await sb.from('projekte').delete().eq('id',id);pgProj();}
async function pgProjDetail(id){ld();const[{data:p},{data:bt},{data:mat},{data:std},{data:ang},{data:abn}]=await Promise.all([sb.from('projekte').select('*').eq('id',id).single(),sb.from('bautagebuch').select('*').eq('projekt_id',id).order('datum',{ascending:false}),sb.from('material').select('*').eq('projekt_id',id),sb.from('stunden').select('*').eq('projekt_id',id),sb.from('angebote').select('*').eq('projekt_id',id),sb.from('abnahmen').select('*').eq('projekt_id',id).order('datum',{ascending:false})]);const kostenStunden=(std||[]).reduce((s,r)=>{const mit=_mitarbeiter.find(m=>m.name===r.mitarbeiter_name);const satz=r.stundensatz||mit?.stundensatz||0;return s+(parseFloat(r.stunden)||0)*satz;},0);const kostenMaterial=(mat||[]).reduce((s,r)=>s+(parseFloat(r.preis)||0),0);const gesamtStunden=(std||[]).reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);const gesamtKosten=kostenStunden+kostenMaterial;const mapQ=encodeURIComponent(p?.adresse||'Berlin');sC(`<button class="bk" onclick="pgProj()">← Zurück</button><div class="ph"><div><div class="pt">${p?.name||'Projekt'}</div><div class="ps">${p?.kunde||p?.kunde_name||''} ${p?.adresse?'· '+p.adresse:''}</div></div><button class="bp" onclick="mProjEdit('${id}')" style="background:var(--bg);color:var(--text);border:1px solid var(--border)">Bearbeiten</button></div><div class="kosten-box"><div class="kosten-box-header"><span class="kosten-box-title">Kostenübersicht</span><span style="font-size:11px;color:var(--text-ter)">automatisch berechnet</span></div><div class="kosten-row"><span class="kosten-label">Stunden (${gesamtStunden.toFixed(1)} h)</span><span class="kosten-val">${fmtEur(kostenStunden)}</span></div><div class="kosten-row"><span class="kosten-label">Material (${(mat||[]).length} Pos.)</span><span class="kosten-val">${fmtEur(kostenMaterial)}</span></div><div class="kosten-total"><span class="kosten-total-label">Gesamtkosten</span><span class="kosten-total-val">${fmtEur(gesamtKosten)}</span></div><div class="kosten-actions"><button class="kosten-btn kosten-btn-ang" onclick="angAusKosten('${id}','${p?.name||''}','${p?.kunde||p?.kunde_name||''}',${kostenStunden},${kostenMaterial})">→ Angebot</button><button class="kosten-btn kosten-btn-rech" onclick="rechAusKosten('${id}','${p?.kunde||p?.kunde_name||''}',${gesamtKosten})">→ Rechnung</button></div></div>${p?.adresse?`<div class="map-wrap"><iframe src="https://maps.google.com/maps?q=${mapQ}&output=embed&z=15" allowfullscreen></iframe></div>`:''}<div class="sh">Bautagebuch (${(bt||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Einträge</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mBt('${id}')">+ Eintrag</button></div><table><thead><tr><th>Datum</th><th>Beschreibung</th><th>Zeit</th><th></th></tr></thead><tbody>${!(bt&&bt.length)?'<tr><td colspan="4"><div class="em" style="padding:20px"><div class="em-t">Keine Einträge</div></div></td></tr>':bt.map(e=>`<tr><td>${fmtDatum(e.datum)}</td><td style="max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${e.beschreibung||'-'}</td><td style="white-space:nowrap;color:var(--text-sec)">${e.zeit_von||'-'} – ${e.zeit_bis||'-'}</td><td style="white-space:nowrap"><button onclick="loadAndExportBt('${e.id}','${p?.name||''}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)">📄</button><button onclick="delBt('${e.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Abnahmen (${(abn||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Abnahmen</span><button class="bp" style="padding:6px 12px;font-size:12px;background:var(--green)" onclick="mAbnahme('${id}','${p?.name||''}','${p?.kunde||p?.kunde_name||''}')">+ Abnahme</button></div><table><thead><tr><th>Datum</th><th>Auftraggeber</th><th>Mängel</th><th></th></tr></thead><tbody>${!(abn&&abn.length)?'<tr><td colspan="4"><div class="em" style="padding:20px"><div class="em-t">Keine Abnahmen</div></div></td></tr>':abn.map(a=>`<tr><td>${fmtDatum(a.datum)}</td><td>${a.auftraggeber||'-'}</td><td>${a.maengel?'<span class="bd bd-r">Ja</span>':'<span class="bd bd-g">Keine</span>'}</td><td><button onclick="exportAbnahmePDF(${JSON.stringify(a).replace(/'/g,'&#39;').replace(/"/g,'&quot;')})" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)">📄</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Angebote (${(ang||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Angebote</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mAng('${id}','${p?.kunde||p?.kunde_name||''}')">+ Angebot</button></div><table><thead><tr><th>Nr.</th><th>Titel</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(ang&&ang.length)?'<tr><td colspan="5"><div class="em" style="padding:20px"><div class="em-t">Keine Angebote</div></div></td></tr>':ang.map(a=>`<tr style="cursor:pointer" onclick="mAngEdit('${a.id}','${id}')"><td style="font-family:monospace;font-size:11px;color:var(--text-ter)">${a.nummer||'-'}</td><td>${a.titel||'-'}</td><td><b>${fmtEur(a.gesamt)}</b></td><td><span class="bd ${a.status==='angenommen'?'bd-g':a.status==='abgelehnt'?'bd-r':'bd-o'}">${a.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="event.stopPropagation();angToRech('${a.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)" title="Zu Rechnung">🧾</button><button onclick="event.stopPropagation();delAng('${a.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Material (${(mat||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Material</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mMat2('${id}')">+ Material</button></div><table><thead><tr><th>Material</th><th>Menge</th><th>Preis</th><th></th></tr></thead><tbody>${!(mat&&mat.length)?'<tr><td colspan="4"><div class="em" style="padding:20px"><div class="em-t">Kein Material</div></div></td></tr>':mat.map(m=>`<tr onclick="mMatEdit('${m.id}','${m.name||''}','${m.menge||''}','${m.preis||''}')" style="cursor:pointer"><td><span style="font-weight:500">${m.name||'-'}</span></td><td style="color:var(--text-sec)">${m.menge||'-'}</td><td>${m.preis?fmtEur(m.preis):'-'}</td><td><button onclick="event.stopPropagation();delMat('${m.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Stunden (${(std||[]).length})</div><div class="tc" style="overflow-x:auto"><div class="th"><span class="th-t">Stunden</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mStd2('${id}')">+ Stunden</button></div><table><thead><tr><th>Datum</th><th>Mitarbeiter</th><th>Std</th><th>Kosten</th><th></th></tr></thead><tbody>${!(std&&std.length)?'<tr><td colspan="5"><div class="em" style="padding:20px"><div class="em-t">Keine Stunden</div></div></td></tr>':std.map(s=>{const mit=_mitarbeiter.find(m=>m.name===s.mitarbeiter_name);const satz=s.stundensatz||mit?.stundensatz||0;const kosten=(parseFloat(s.stunden)||0)*satz;return`<tr style="cursor:pointer" onclick="mStdEdit('${s.id}','${s.mitarbeiter_name||''}','${s.datum||''}','${s.stunden||0}','${satz}','${id}')"><td>${fmtDatum(s.datum)}</td><td>${s.mitarbeiter_name||'-'}</td><td><b>${s.stunden||0} h</b></td><td>${satz>0?fmtEur(kosten):'-'}</td><td><button onclick="event.stopPropagation();delStd('${s.id}','${id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`;}).join('')}</tbody></table></div><div class="sh">Fotos</div><div class="photo-up" onclick="document.getElementById('fi').click()"><input type="file" id="fi" accept="image/*" multiple style="display:none" onchange="upFotos('${id}')"><div style="font-size:20px;margin-bottom:4px">📷</div><div style="font-size:13px;font-weight:500">Fotos hinzufügen</div></div><div id="fp" class="photo-prev"></div>`);}
async function mAngEdit(aid,pid){const{data:a}=await sb.from('angebote').select('*').eq('id',aid).single();if(!a)return;const pos=JSON.parse(a.positionen||'[]');oM(`${modalHeader('Angebot bearbeiten')}<div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${a.nummer||''}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${a.datum||heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" value="${a.titel||''}"></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${a.kunde||''}"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap">${pos.map(p=>`<div class="offer-row"><input value="${p.name||''}" class="pos-name"><input value="${p.preis||0}" type="number" class="pos-price price-inp" oninput="calcTotal()"></div>`).join('')}</div><button type="button" onclick="addPos()" style="margin-top:6px;padding:8px 14px;background:var(--bg);border:1.5px dashed var(--border);border-radius:var(--radius);font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec);width:100%">+ Position</button><div class="offer-total">Gesamt: <span id="tot">${fmtEur(a.gesamt)}</span></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen"${a.status==='offen'?' selected':''}>Offen</option><option value="angenommen"${a.status==='angenommen'?' selected':''}>Angenommen</option><option value="abgelehnt"${a.status==='abgelehnt'?' selected':''}>Abgelehnt</option></select></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delAng('${aid}','${pid}');cM()">Löschen</button><button class="bs" onclick="saveAngEdit('${aid}','${pid}')">Speichern</button></div>`);}
async function saveAngEdit(aid,pid){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').update({nummer:document.getElementById('f-nr').value,titel:t,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:document.getElementById('f-s').value}).eq('id',aid);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
function mStdEdit(id,name,datum,stunden,satz,pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}"${m.name===name?' selected':''}>${m.name}</option>`).join('');oM(`${modalHeader('Stunden bearbeiten')}<div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" value="${satz||''}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.5" value="${stunden||''}"></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delStd('${id}','${pid}');cM()">Löschen</button><button class="bs" onclick="saveStdEdit('${id}','${pid}')">Speichern</button></div>`);}
async function saveStdEdit(id,pid){const s=document.getElementById('f-s').value;if(!s){alert('Stunden fehlen!');return;}const satz=parseFloat(document.getElementById('f-satz').value)||0;const{error}=await sb.from('stunden').update({mitarbeiter_name:document.getElementById('f-n').value,datum:document.getElementById('f-d').value,stunden:parseFloat(s),stundensatz:satz,kosten:(parseFloat(s)||0)*satz}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
async function angAusKosten(pid,pname,kunde,kostenStd,kostenMat){const nr='A-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const pos=[];if(kostenStd>0)pos.push({name:'Lohnkosten',preis:kostenStd});if(kostenMat>0)pos.push({name:'Materialkosten',preis:kostenMat});const gesamt=kostenStd+kostenMat;oM(`${modalHeader('Angebot aus Projektkosten')}<div style="background:var(--p-light);border-radius:10px;padding:12px;margin-bottom:16px"><div style="font-size:13px;font-weight:600;color:var(--p)">${pname||'Projekt'}</div><div style="font-size:12px;color:var(--text-sec);margin-top:3px">Lohn: ${fmtEur(kostenStd)} · Material: ${fmtEur(kostenMat)}</div></div><div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" value="Arbeiten ${pname||''}"></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${kunde||''}"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap">${pos.map(p=>`<div class="offer-row"><input value="${p.name}" class="pos-name"><input value="${p.preis.toFixed(2)}" type="number" class="pos-price price-inp" oninput="calcTotal()"></div>`).join('')}</div><button type="button" onclick="addPos()" style="margin-top:6px;padding:8px 14px;background:var(--bg);border:1.5px dashed var(--border);border-radius:var(--radius);font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec);width:100%">+ Position</button><div class="offer-total">Gesamt: <span id="tot">${fmtEur(gesamt)}</span></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAngMitPid('${pid}')">Speichern</button></div>`);}
async function saveAngMitPid(pid){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').insert({nummer:document.getElementById('f-nr').value,titel:t,projekt_id:pid,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:'offen',user_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
async function rechAusKosten(pid,kunde,betrag){if(!confirm(`Rechnung über ${fmtEur(betrag)} erstellen?`))return;const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('rechnungen').insert({rechnungsnummer:nr,projekt_id:pid,kunde:kunde,datum:heute(),betrag:betrag,status:'offen'});if(error){alert('Fehler: '+error.message);return;}if(confirm('Rechnung erstellt! Jetzt zur Rechnung?'))go('rech');else pgProjDetail(pid);}
async function angToRech(aid,pid){const{data:a}=await sb.from('angebote').select('*').eq('id',aid).single();if(!a)return;if(!confirm('Angebot in Rechnung umwandeln?'))return;const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('rechnungen').insert({rechnungsnummer:nr,projekt_id:pid||a.projekt_id,kunde:a.kunde,datum:heute(),betrag:a.gesamt,status:'offen'});if(error){alert('Fehler: '+error.message);return;}await sb.from('angebote').update({status:'angenommen'}).eq('id',aid);if(confirm('Rechnung erstellt! Jetzt zur Rechnung?'))go('rech');else pgProjDetail(pid);}
async function mProjEdit(id){const{data:p}=await sb.from('projekte').select('*').eq('id',id).single();const{data:ku}=await sb.from('kunden').select('id,name');oM(`${modalHeader('Projekt bearbeiten')}<div class="fg"><label>PROJEKTNAME *</label><input id="f-n" value="${p.name||''}"></div><div class="fg"><label>KUNDE</label><select id="f-ku"><option value="">- Kein Kunde -</option>${(ku||[]).map(k=>`<option value="${k.id}" data-n="${k.name}"${k.id===p.kunden_id?' selected':''}>${k.name}</option>`).join('')}</select></div><div class="fg"><label>ADRESSE</label><input id="f-adr" value="${p.adresse||''}"></div><div class="fg"><label>STATUS</label><select id="f-st"><option value="Aktiv"${p.status==='Aktiv'?' selected':''}>Aktiv</option><option value="Pausiert"${p.status==='Pausiert'?' selected':''}>Pausiert</option><option value="Abgeschlossen"${p.status==='Abgeschlossen'?' selected':''}>Abgeschlossen</option></select></div><div class="fg"><label>BESCHREIBUNG</label><textarea id="f-desc" rows="3">${p.beschreibung||''}</textarea></div><div class="fr"><div class="fg"><label>START</label><input id="f-start" type="date" value="${p.datum_start||''}"></div><div class="fg"><label>ENDE</label><input id="f-end" type="date" value="${p.datum_end||''}"></div></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delProj('${id}')">Löschen</button><button class="bs" onclick="saveProjEdit('${id}')">Speichern</button></div>`);}
async function saveProjEdit(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Projektname fehlt!');return;}const s=document.getElementById('f-ku');const ki=s.value||null,kn=ki?s.options[s.selectedIndex].dataset.n:'';const{error}=await sb.from('projekte').update({name:n,kunden_id:ki,kunde_name:kn,kunde:kn,adresse:document.getElementById('f-adr').value,beschreibung:document.getElementById('f-desc').value,status:document.getElementById('f-st').value,datum_start:document.getElementById('f-start').value||null,datum_end:document.getElementById('f-end').value||null}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(id);}
async function upFotos(pid){const files=document.getElementById('fi').files;const prev=document.getElementById('fp');for(const f of files){const r=new FileReader();r.onload=e=>{const i=document.createElement('img');i.src=e.target.result;i.className='pt-img';i.onclick=()=>window.open(e.target.result,'_blank');i.style.cursor='pointer';prev.appendChild(i);};r.readAsDataURL(f);await sb.storage.from('fotos').upload(`${pid}/${Date.now()}_${f.name}`,f).catch(()=>{});}}
async function delBt(id,pid){if(!confirm('Eintrag löschen?'))return;await sb.from('bautagebuch').delete().eq('id',id);pgProjDetail(pid);}
async function delMat(id,pid){if(!confirm('Material löschen?'))return;await sb.from('material').delete().eq('id',id);pgProjDetail(pid);}
async function delStd(id,pid){if(!confirm('Stunden löschen?'))return;await sb.from('stunden').delete().eq('id',id);pgProjDetail(pid);}
async function delAng(id,pid){if(!confirm('Angebot löschen?'))return;await sb.from('angebote').delete().eq('id',id);pgProjDetail(pid);}
function mMatEdit(id,name,menge,preis){oM(`${modalHeader('Material bearbeiten')}<div class="fg"><label>MATERIALNAME *</label><input id="f-n" value="${name}"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" value="${menge}"></div><div class="fg"><label>PREIS</label><input id="f-pr" type="number" step="0.01" value="${preis}"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMatEdit('${id}')">Speichern</button></div>`);}
async function saveMatEdit(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const{error}=await sb.from('material').update({name:n,menge:document.getElementById('f-m').value,preis:parseFloat(document.getElementById('f-pr').value)||null}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgMat();}
async function pgTermine(){ld();try{const h=new Date();const[{data},{data:proj}]=await Promise.all([sb.from('termine').select('*').order('datum'),sb.from('projekte').select('id,name')]);const yr=h.getFullYear(),mo=h.getMonth();const firstDay=new Date(yr,mo,1).getDay();const dim=new Date(yr,mo+1,0).getDate();const monate=['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];let cc='';const pad=n=>String(n).padStart(2,'0');for(let i=0;i<(firstDay===0?6:firstDay-1);i++)cc+=`<div class="cal-day" style="background:var(--bg)"></div>`;for(let d=1;d<=dim;d++){const ds=`${yr}-${pad(mo+1)}-${pad(d)}`;const de=(data||[]).filter(t=>t.datum===ds);const it=ds===heute();cc+=`<div class="cal-day${it?' today':''}" onclick='mTermin("${ds}",${JSON.stringify(proj||[]).replace(/"/g,"&quot;")})'><div class="cal-dn${it?' cur':''}">${d}</div>${de.slice(0,2).map(e=>`<div class="cal-ev">${e.titel||'Termin'}</div>`).join('')}</div>`;}const up=(data||[]).filter(t=>t.datum>=heute()).slice(0,10);sC(`<div class="ph"><div><div class="pt">Termine</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick='mTermin("",${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Neuer Termin</button></div><div class="cal"><div class="cal-head"><div style="font-size:14px;font-weight:700">${monate[mo]} ${yr}</div></div><div class="cal-grid"><div class="cal-day-h">Mo</div><div class="cal-day-h">Di</div><div class="cal-day-h">Mi</div><div class="cal-day-h">Do</div><div class="cal-day-h">Fr</div><div class="cal-day-h">Sa</div><div class="cal-day-h">So</div>${cc}</div></div><div class="sh">Kommende Termine</div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Datum</th><th>Zeit</th><th>Titel</th><th>Status</th><th></th></tr></thead><tbody>${!up.length?'<tr><td colspan="5"><div class="em" style="padding:20px"><div class="em-t">Keine Termine</div></div></td></tr>':up.map(t=>`<tr style="cursor:pointer" onclick="mTerminEdit('${t.id}','${t.titel||''}','${t.datum||''}','${t.uhrzeit||''}','${t.status||''}','${t.projekt_id||''}',${JSON.stringify(proj||[]).replace(/'/g,'&#39;').replace(/"/g,'&quot;')})"><td>${fmtDatum(t.datum)}</td><td style="color:var(--text-sec)">${t.uhrzeit||'-'}</td><td><span style="font-weight:500">${t.titel||'-'}</span></td><td><span class="bd ${t.status==='erledigt'?'bd-g':t.status==='abgesagt'?'bd-r':'bd-b'}">${t.status||'geplant'}</span></td><td><button onclick="event.stopPropagation();delTermin('${t.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mTermin(datum,proj){oM(`${modalHeader('Neuer Termin')}<div class="fg"><label>TITEL *</label><input id="f-t" placeholder="z.B. Baustellenbegehung"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fr"><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>UHRZEIT</label><input id="f-u" type="time" value="08:00"></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="geplant">Geplant</option><option value="erledigt">Erledigt</option><option value="abgesagt">Abgesagt</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveTermin('')">Speichern</button></div>`);}
function mTerminEdit(id,titel,datum,uhrzeit,status,pid,proj){oM(`${modalHeader('Termin bearbeiten')}<div class="fg"><label>TITEL *</label><input id="f-t" value="${titel}"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fr"><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>UHRZEIT</label><input id="f-u" type="time" value="${uhrzeit||'08:00'}"></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="geplant"${status==='geplant'?' selected':''}>Geplant</option><option value="erledigt"${status==='erledigt'?' selected':''}>Erledigt</option><option value="abgesagt"${status==='abgesagt'?' selected':''}>Abgesagt</option></select></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delTermin('${id}')">Löschen</button><button class="bs" onclick="saveTermin('${id}')">Speichern</button></div>`);}
async function saveTermin(id){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const o={titel:t,projekt_id:document.getElementById('f-p').value||null,datum:document.getElementById('f-d').value,uhrzeit:document.getElementById('f-u').value,status:document.getElementById('f-s').value,user_id:me.id};const{error}=id?await sb.from('termine').update(o).eq('id',id):await sb.from('termine').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgTermine();}
async function delTermin(id){if(!confirm('Termin löschen?'))return;await sb.from('termine').delete().eq('id',id);cM();pgTermine();}
async function pgAngebote(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('angebote').select('*').order('created_at',{ascending:false}),sb.from('projekte').select('id,name')]);sC(`<div class="ph"><div><div class="pt">Angebote</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick='mAng("","",${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Neues Angebot</button></div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Nr.</th><th>Datum</th><th>Titel</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Angebote</div></div></td></tr>':data.map(a=>`<tr style="cursor:pointer" onclick="mAngEdit('${a.id}',null)"><td style="font-family:monospace;font-size:11px;color:var(--text-ter)">${a.nummer||'-'}</td><td>${fmtDatum(a.datum)}</td><td><span style="font-weight:500">${a.titel||'-'}</span></td><td><b>${fmtEur(a.gesamt)}</b></td><td><span class="bd ${a.status==='angenommen'?'bd-g':a.status==='abgelehnt'?'bd-r':'bd-o'}">${a.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="event.stopPropagation();angToRech('${a.id}',null)" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)" title="Zu Rechnung">🧾</button><button onclick="event.stopPropagation();delAngD('${a.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mAng(pid,kn,proj){const nr='A-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);oM(`${modalHeader('Angebot erstellen')}<div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" placeholder="z.B. Sanierungsarbeiten"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${kn||''}" placeholder="Kundenname"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap"><div class="offer-row"><input placeholder="Leistung" class="pos-name"><input placeholder="Preis" type="number" class="pos-price price-inp" oninput="calcTotal()"></div></div><button type="button" onclick="addPos()" style="margin-top:6px;padding:8px 14px;background:var(--bg);border:1.5px dashed var(--border);border-radius:var(--radius);font-size:12px;font-weight:600;cursor:pointer;color:var(--text-sec);width:100%">+ Position</button><div class="offer-total">Gesamt: <span id="tot">0,00 €</span></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen">Offen</option><option value="angenommen">Angenommen</option><option value="abgelehnt">Abgelehnt</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAng()">Speichern</button></div>`);}
function addPos(){const w=document.getElementById('pos-wrap');const r=document.createElement('div');r.className='offer-row';r.innerHTML='<input placeholder="Leistung" class="pos-name"><input placeholder="Preis" type="number" class="pos-price price-inp" oninput="calcTotal()">';w.appendChild(r);}
function calcTotal(){let t=0;document.querySelectorAll('.pos-price').forEach(p=>t+=parseFloat(p.value)||0);document.getElementById('tot').textContent=fmtEur(t);}
async function saveAng(){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').insert({nummer:document.getElementById('f-nr').value,titel:t,projekt_id:document.getElementById('f-p').value||null,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:document.getElementById('f-s').value,user_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgAngebote();}
async function delAngD(id){if(!confirm('Angebot löschen?'))return;await sb.from('angebote').delete().eq('id',id);pgAngebote();}
async function pgMit(){ld();try{const{data}=await sb.from('mitarbeiter').select('*').order('name');sC(`<div class="ph"><div><div class="pt">Mitarbeiter</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick="mMitarbeiter()">+ Neu</button></div>${!(data&&data.length)?'<div class="em"><div class="em-t">Noch keine Mitarbeiter</div></div>':`<div class="gr">${data.map(m=>`<div class="ca" onclick='mMitarbeiter(${JSON.stringify(m).replace(/'/g,"&#39;")})' style="cursor:pointer"><div style="display:flex;align-items:center;gap:12px"><div style="width:38px;height:38px;background:${m.farbe||'var(--p-light)'};border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:#fff;flex-shrink:0">${(m.name||'?')[0].toUpperCase()}</div><div style="flex:1"><div class="ca-t">${m.name||'-'}</div><div class="ca-s">${m.rolle||'Mitarbeiter'}${m.stundensatz?' · '+fmtEur(m.stundensatz)+'/h':''}</div></div></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mMitarbeiter(m={}){const farben=['#1D4ED8','#15803D','#B45309','#DC2626','#7C3AED','#0369A1','#C2410C','#BE185D'];oM(`${modalHeader(m.id?'Mitarbeiter bearbeiten':'Neuer Mitarbeiter')}<div class="fg"><label>NAME *</label><input id="f-n" value="${m.name||''}" placeholder="Max Mustermann"></div><div class="fr"><div class="fg"><label>TELEFON</label><input id="f-tel" value="${m.telefon||''}" placeholder="+49 176 ..."></div><div class="fg"><label>ROLLE</label><select id="f-ro"><option value="Mitarbeiter"${m.rolle==='Mitarbeiter'?' selected':''}>Mitarbeiter</option><option value="Bauleiter"${m.rolle==='Bauleiter'?' selected':''}>Bauleiter</option><option value="Azubi"${m.rolle==='Azubi'?' selected':''}>Azubi</option><option value="Subunternehmer"${m.rolle==='Subunternehmer'?' selected':''}>Subunternehmer</option></select></div></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-sh" type="number" step="0.5" value="${m.stundensatz||''}" placeholder="45"></div><div class="fg"><label>FARBE</label><div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:4px">${farben.map(f=>`<div onclick="document.getElementById('f-farbe').value='${f}';document.querySelectorAll('.farb-btn').forEach(b=>b.style.outline='none');this.style.outline='3px solid var(--text)';this.style.outlineOffset='2px'" class="farb-btn" style="width:28px;height:28px;border-radius:7px;background:${f};cursor:pointer;outline:${(m.farbe||'#1D4ED8')===f?'3px solid var(--text)':'none'};outline-offset:2px"></div>`).join('')}<input type="hidden" id="f-farbe" value="${m.farbe||'#1D4ED8'}"></div></div><div class="ma">${m.id?`<button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delMitarbeiter('${m.id}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveMitarbeiter('${m.id||''}')">Speichern</button></div>`);}
async function saveMitarbeiter(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const o={name:n,telefon:document.getElementById('f-tel').value,rolle:document.getElementById('f-ro').value,stundensatz:parseFloat(document.getElementById('f-sh').value)||null,farbe:document.getElementById('f-farbe').value};const{error}=id?await sb.from('mitarbeiter').update(o).eq('id',id):await sb.from('mitarbeiter').insert(o);if(error){alert('Fehler: '+error.message);return;}await loadMitarbeiter();cM();pgMit();}
