async function pgStd(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('stunden').select('*').order('datum',{ascending:false}),sb.from('projekte').select('id,name')]);const total=(data||[]).reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);const totalKosten=(data||[]).reduce((s,r)=>{const mit=_mitarbeiter.find(m=>m.name===r.mitarbeiter_name);const satz=r.stundensatz||mit?.stundensatz||0;return s+(parseFloat(r.stunden)||0)*satz;},0);sC(`<div class="ph"><div><div class="pt">Stunden</div><div class="ps">${total.toFixed(1)} h gesamt · ${fmtEur(totalKosten)}</div></div><button class="bp" onclick='mStdAllg(${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Eintragen</button></div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Datum</th><th>Mitarbeiter</th><th>Projekt</th><th>Std</th><th>Kosten</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Einträge</div></div></td></tr>':data.map(s=>{const mit=_mitarbeiter.find(m=>m.name===s.mitarbeiter_name);const satz=s.stundensatz||mit?.stundensatz||0;const kosten=(parseFloat(s.stunden)||0)*satz;return`<tr><td>${fmtDatum(s.datum)}</td><td>${s.mitarbeiter_name||'-'}</td><td style="color:var(--text-sec)">${(proj||[]).find(p=>p.id===s.projekt_id)?.name||'-'}</td><td><b>${s.stunden||0} h</b></td><td>${satz>0?fmtEur(kosten):'-'}</td><td><button onclick="delStdD('${s.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`;}).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mStd2(pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}">${m.name}${m.stundensatz?' ('+fmtEur(m.stundensatz)+'/h)':''}</option>`).join('');oM(`${modalHeader('Stunden eintragen')}<input type="hidden" id="f-p" value="${pid}"><div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" placeholder="wird automatisch befüllt"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.5" min="0.5" max="24" placeholder="8"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveStd()">Speichern</button></div>`);}
function mStdAllg(proj){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}">${m.name}${m.stundensatz?' ('+fmtEur(m.stundensatz)+'/h)':''}</option>`).join('');oM(`${modalHeader('Stunden eintragen')}<div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">— Kein Projekt —</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" placeholder="wird automatisch befüllt"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.5" min="0.5" max="24" placeholder="8"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveStd()">Speichern</button></div>`);}
