async function pgMat(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('material').select('*').order('created_at',{ascending:false}),sb.from('projekte').select('id,name')]);const totalWert=(data||[]).reduce((s,r)=>s+(parseFloat(r.preis)||0),0);sC(`<div class="ph"><div><div class="pt">Material</div><div class="ps">${(data||[]).length} Einträge · ${fmtEur(totalWert)}</div></div><button class="bp" onclick='mMatAllg(${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Hinzufügen</button></div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Material</th><th>Projekt</th><th>Menge</th><th>Preis</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="5"><div class="em" style="padding:30px"><div class="em-t">Kein Material</div></div></td></tr>':data.map(m=>`<tr onclick="mMatEdit('${m.id}','${m.name||''}','${m.menge||''}','${m.preis||''}')" style="cursor:pointer"><td><span style="font-weight:500">${m.name||'-'}</span></td><td style="color:var(--text-sec)">${(proj||[]).find(p=>p.id===m.projekt_id)?.name||'-'}</td><td style="color:var(--text-sec)">${m.menge||'-'}</td><td>${m.preis?fmtEur(m.preis):'-'}</td><td><button onclick="event.stopPropagation();delMatD('${m.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mMat2(pid){oM(`${modalHeader('Material hinzufügen')}<input type="hidden" id="f-p" value="${pid}"><div class="fg"><label>MATERIALNAME *</label><input id="f-n" placeholder="z.B. Zement"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" placeholder="50 Säcke"></div><div class="fg"><label>PREIS</label><input id="f-pr" type="number" step="0.01" placeholder="0,00"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMat()">Speichern</button></div>`);}
function mMatAllg(proj){oM(`${modalHeader('Material hinzufügen')}<div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>MATERIALNAME *</label><input id="f-n" placeholder="z.B. Zement"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" placeholder="50 Säcke"></div><div class="fg"><label>PREIS</label><input id="f-pr" type="number" step="0.01" placeholder="0,00"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMat()">Speichern</button></div>`);}
async function saveMat(){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const{error}=await sb.from('material').insert({projekt_id:document.getElementById('f-p').value||null,name:n,menge:document.getElementById('f-m').value,preis:parseFloat(document.getElementById('f-pr').value)||null});if(error){alert('Fehler: '+error.message);return;}cM();pgMat();}
async function delMatD(id){if(!confirm('Material löschen?'))return;await sb.from('material').delete().eq('id',id);pgMat();}
async function pgRech(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('rechnungen').select('*').order('datum',{ascending:false}),sb.from('projekte').select('id,name')]);const paid=(data||[]).filter(r=>r.status==='bezahlt').reduce((s,r)=>s+(parseFloat(r.betrag)||0),0);const open=(data||[]).filter(r=>r.status==='offen').reduce((s,r)=>s+(parseFloat(r.betrag)||0),0);window._rProj=proj||[];sC(`<div class="ph"><div><div class="pt">Rechnungen</div><div class="ps">${(data||[]).length} Einträge</div></div><button class="bp" onclick="mRech(window._rProj)">+ Erstellen</button></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px"><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:16px"><div style="font-size:11px;font-weight:700;color:var(--green);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">Bezahlt</div><div style="font-size:22px;font-weight:800;color:var(--text);letter-spacing:-0.5px">${fmtEur(paid)}</div></div><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:16px"><div style="font-size:11px;font-weight:700;color:var(--yellow);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">Ausstehend</div><div style="font-size:22px;font-weight:800;color:var(--text);letter-spacing:-0.5px">${fmtEur(open)}</div></div></div><div class="tc" style="overflow-x:auto"><table><thead><tr><th>Nr.</th><th>Datum</th><th>Kunde</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Rechnungen</div></div></td></tr>':data.map(r=>`<tr style="cursor:pointer" onclick="mRechEdit('${r.id}','${r.rechnungsnummer||''}','${r.datum||''}','${r.kunde||''}','${r.betrag||''}','${r.status||'offen'}','${r.projekt_id||''}')"><td style="font-family:monospace;font-size:11px;color:var(--text-ter);white-space:nowrap">${r.rechnungsnummer||'-'}</td><td style="white-space:nowrap">${fmtDatum(r.datum)}</td><td style="font-weight:500">${r.kunde||'-'}</td><td style="white-space:nowrap"><b>${fmtEur(r.betrag)}</b></td><td><span class="bd ${r.status==='bezahlt'?'bd-g':r.status==='offen'?'bd-o':'bd-r'}">${r.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="event.stopPropagation();exportRechPDF('${r.id}','${r.rechnungsnummer||''}','${r.datum||''}','${r.kunde||''}','${r.betrag||''}','${r.status||''}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--text-sec)" title="PDF">📄</button><button onclick="event.stopPropagation();delRech('${r.id}')" style="background:none;border:none;cursor:pointer;padding:4px;color:var(--red)">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-t">${e.message}</div></div>`);}}
function mRech(proj){const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);oM(`${modalHeader('Rechnung erstellen')}<div class="fr"><div class="fg"><label>RECHNUNGSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE *</label><input id="f-ku" placeholder="Müller GmbH"></div><div class="fg"><label>BETRAG *</label><input id="f-b" type="number" step="0.01" placeholder="0,00"></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen">Offen</option><option value="bezahlt">Bezahlt</option><option value="storniert">Storniert</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveRech('')">Erstellen</button></div>`);}
function mRechEdit(id,nr,datum,kunde,betrag,status,pid){oM(`${modalHeader('Rechnung bearbeiten')}<div class="fr"><div class="fg"><label>RECHNUNGSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(window._rProj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE *</label><input id="f-ku" value="${kunde}"></div><div class="fg"><label>BETRAG *</label><input id="f-b" type="number" step="0.01" value="${betrag}"></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen"${status==='offen'?' selected':''}>Offen</option><option value="bezahlt"${status==='bezahlt'?' selected':''}>Bezahlt</option><option value="storniert"${status==='storniert'?' selected':''}>Storniert</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveRech('${id}')">Speichern</button></div>`);}
async function saveRech(id){const ku=document.getElementById('f-ku').value.trim(),b=document.getElementById('f-b').value;if(!ku||!b){alert('Kunde und Betrag fehlen!');return;}const o={rechnungsnummer:document.getElementById('f-nr').value,projekt_id:document.getElementById('f-p').value||null,kunde:ku,datum:document.getElementById('f-d').value,betrag:parseFloat(b),status:document.getElementById('f-s').value};const{error}=id?await sb.from('rechnungen').update(o).eq('id',id):await sb.from('rechnungen').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgRech();}
async function delRech(id){if(!confirm('Rechnung löschen?'))return;await sb.from('rechnungen').delete().eq('id',id);pgRech();}
function exportRechPDF(id,nr,datum,kunde,betrag,status){const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[37,99,235];const grau=[107,114,128];const L=20,R=190,W=170;doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');doc.setFillColor(255,255,255);doc.roundedRect(L-5,12,W+10,38,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,12,W+10,38,3,3,'S');doc.setTextColor(...blau);doc.setFontSize(20);doc.setFont('helvetica','bold');doc.text('RECHNUNG',L,28);doc.setFontSize(9);doc.setFont('helvetica','normal');doc.setTextColor(...grau);doc.text(nr,L,36);doc.text(settings.firma||'Alem Facility PRO',R,24,'right');doc.text(settings.adresse||'',R,31,'right');doc.text(fmtDatum(datum),R,38,'right');let y=64;doc.setFillColor(255,255,255);doc.roundedRect(L-5,y-6,W+10,24,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,y-6,W+10,24,3,3,'S');doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('RECHNUNGSEMPFAENGER',L,y+1);doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(12);doc.text(kunde||'-',L,y+11);y+=36;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('LEISTUNGEN',L,y);y+=6;doc.setFillColor(249,250,251);doc.rect(L-5,y,W+10,8,'F');doc.setFontSize(9);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('Beschreibung',L,y+5);doc.text('Betrag',R,y+5,'right');y+=12;const rechnungBetrag=parseFloat(betrag||0);const mwstSatz=settings.mwst||19;const netto=rechnungBetrag/(1+mwstSatz/100);doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);doc.text('Arbeitsleistung und Material',L,y);doc.text(fmtEur(netto),R,y,'right');y+=10;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFontSize(9);doc.setTextColor(...grau);doc.text('Zwischensumme (netto)',L,y);doc.text(fmtEur(netto),R,y,'right');y+=7;const mwstBetrag=rechnungBetrag-netto;doc.text('MwSt ('+mwstSatz+' %)',L,y);doc.text(fmtEur(mwstBetrag),R,y,'right');y+=10;doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFont('helvetica','bold');doc.setTextColor(17,24,39);doc.setFontSize(14);doc.text('Gesamtbetrag',L,y);doc.text(fmtEur(rechnungBetrag),R,y,'right');y+=18;if(settings.iban){doc.setFillColor(239,246,255);doc.roundedRect(L-5,y-6,W+10,32,3,3,'F');doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.text('BANKVERBINDUNG',L,y+1);y+=8;doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);doc.text('IBAN: '+(settings.iban||'-'),L,y);y+=6;if(settings.bank)doc.text('Bank: '+settings.bank,L,y);y+=6;if(settings.zahlungsziel)doc.text('Zahlungsziel: '+settings.zahlungsziel+' Tage',L,y);}doc.setDrawColor(229,231,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Alem Facility PRO · '+new Date().toLocaleDateString('de-DE'),L,283);if(settings.ustid)doc.text('USt-ID: '+settings.ustid,R,283,'right');doc.save('Rechnung_'+nr+'.pdf');}
async function mBt(pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}">${m.name}</option>`).join('');const schnell=['Maurerarbeiten','Fenster eingebaut','Elektroarbeiten','Sanitärarbeiten','Gerüst auf/abgebaut','Materiallieferung','Bauabnahme','Mangel festgestellt','Malerarbeiten','Metallbauarbeiten','Zimmerarbeiten','Dacharbeiten'];oM(`${modalHeader('Bautagesprotokoll')}<div style="background:var(--p-light);border-radius:var(--radius);padding:12px;margin-bottom:16px"><div style="display:flex;align-items:center;gap:8px"><span style="font-size:12px;color:var(--text-sec);font-weight:600">Datum:</span><input id="f-dat" type="date" value="${heute()}" style="border:none;background:transparent;font-weight:700;color:var(--p);font-size:13px;outline:none"></div></div><div class="fr"><div class="fg"><label>ZEIT VON</label><input id="f-zv" type="time" value="07:00"></div><div class="fg"><label>ZEIT BIS</label><input id="f-zb" type="time" value="16:00"></div></div><div class="fg"><label>GEWERK / FIRMA</label><input id="f-gw" placeholder="z.B. Maurer GmbH"></div><div class="fg"><label>ANWESENDE MITARBEITER</label><select id="f-mit"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>TÄTIGKEITEN *</label><div style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:8px">${schnell.map(s=>`<button type="button" onclick="addText('f-desc','${s}')" style="padding:4px 10px;background:var(--bg);border:1.5px solid var(--border);color:var(--text-sec);border-radius:6px;font-size:11px;font-weight:500;cursor:pointer;font-family:inherit;transition:all 0.1s" onmouseover="this.style.borderColor='var(--p)';this.style.color='var(--p)'" onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--text-sec)'">${s}</button>`).join('')}</div><textarea id="f-desc" rows="4" placeholder="Beschreibung der Tätigkeiten..."></textarea></div><div class="fg"><label>VERWENDETES MATERIAL</label><textarea id="f-mat" rows="2" placeholder="z.B. 50 Sack Zement..."></textarea></div><div class="fg"><label>LIEFERUNGEN</label><input id="f-lief" placeholder="z.B. Holzlieferung Firma XY"></div><div class="fg"><label>MÄNGEL / BESONDERHEITEN</label><textarea id="f-maeng" rows="2" placeholder="z.B. Riss in Wand entdeckt..."></textarea></div><div class="fg"><label>FOTOS</label><div class="photo-up" onclick="document.getElementById('bt-fi').click()"><input type="file" id="bt-fi" accept="image/*" multiple style="display:none" onchange="previewBtFotos()"><div style="font-size:20px;margin-bottom:4px">📷</div><div style="font-size:13px;font-weight:500">Fotos hinzufügen</div></div><div id="bt-fp" class="photo-prev"></div></div><div class="fg"><label>UNTERSCHRIFT BAULEITER</label><canvas id="sig-bl" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-bl')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGGEBER</label><canvas id="sig-ag" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-ag')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveBt('${pid}')">Speichern</button></div>`);initSig('sig-bl');initSig('sig-ag');}
function addText(id,txt){const el=document.getElementById(id);el.value+=(el.value?'\n':'')+txt;}
function initSig(id){const c=document.getElementById(id);if(!c)return;const ctx=c.getContext('2d');let drawing=false;const getPos=(e)=>{const r=c.getBoundingClientRect();const t=e.touches?e.touches[0]:e;return{x:(t.clientX-r.left)*(c.width/r.width),y:(t.clientY-r.top)*(c.height/r.height)};};c.addEventListener('mousedown',e=>{drawing=true;const p=getPos(e);ctx.beginPath();ctx.moveTo(p.x,p.y);});c.addEventListener('mousemove',e=>{if(!drawing)return;const p=getPos(e);ctx.lineTo(p.x,p.y);ctx.strokeStyle='#111827';ctx.lineWidth=2;ctx.lineCap='round';ctx.stroke();});c.addEventListener('mouseup',()=>drawing=false);c.addEventListener('touchstart',e=>{e.preventDefault();drawing=true;const p=getPos(e);ctx.beginPath();ctx.moveTo(p.x,p.y);},{passive:false});c.addEventListener('touchmove',e=>{e.preventDefault();if(!drawing)return;const p=getPos(e);ctx.lineTo(p.x,p.y);ctx.strokeStyle='#111827';ctx.lineWidth=2;ctx.lineCap='round';ctx.stroke();},{passive:false});c.addEventListener('touchend',()=>drawing=false);}
function clearSig(id){const c=document.getElementById(id);c.getContext('2d').clearRect(0,0,c.width,c.height);}
function previewBtFotos(){const files=document.getElementById('bt-fi').files;const prev=document.getElementById('bt-fp');prev.innerHTML='';for(const f of files){const r=new FileReader();r.onload=e=>{const i=document.createElement('img');i.src=e.target.result;i.className='pt-img';i.onclick=()=>window.open(e.target.result,'_blank');i.style.cursor='pointer';prev.appendChild(i);};r.readAsDataURL(f);}}
async function saveBt(pid){const d=document.getElementById('f-desc').value.trim();if(!d){alert('Beschreibung fehlt!');return;}const sigBl=document.getElementById('sig-bl').toDataURL();const sigAg=document.getElementById('sig-ag').toDataURL();const dat=document.getElementById('f-dat');const mit=document.getElementById('f-mit');const{error}=await sb.from('bautagebuch').insert({projekt_id:pid,datum:dat?dat.value:heute(),beschreibung:d,gewerk:document.getElementById('f-gw').value,mitarbeiter:mit?mit.value:'',material_verwendet:document.getElementById('f-mat').value,lieferungen:document.getElementById('f-lief').value,maengel:document.getElementById('f-maeng').value,zeit_von:document.getElementById('f-zv').value,zeit_bis:document.getElementById('f-zb').value,unterschrift_bauleiter:sigBl,unterschrift_auftraggeber:sigAg,erstellt_von:me.email});if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
function mAbnahme(pid,pname,kunde){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}">${m.name}</option>`).join('');oM(`${modalHeader('Abnahmeprotokoll')}<div style="background:var(--p-light);border-radius:var(--radius);padding:12px;margin-bottom:16px"><div style="display:flex;justify-content:space-between;align-items:center"><span style="font-size:13px;font-weight:600;color:var(--p)">${pname||'Projekt'}</span><span style="font-size:12px;color:var(--text-sec)">${new Date().toLocaleDateString('de-DE')}</span></div></div><div class="fr"><div class="fg"><label>ORT</label><input id="f-ort" placeholder="z.B. Berlin"></div><div class="fg"><label>AUFTRAGGEBER</label><input id="f-ag" value="${kunde||''}" placeholder="Kunde / Vermieter"></div></div><div class="fg"><label>AUFTRAGNEHMER</label><input id="f-an" value="${settings.firma||''}" placeholder="Ihre Firma"></div><div class="fg"><label>BAULEITER</label><select id="f-bl"><option value="">— Wählen —</option>${mitOpts}</select></div><div class="fg"><label>ERLEDIGTE ARBEITEN</label><div style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:8px">${['Maurerarbeiten','Elektroarbeiten','Sanitärarbeiten','Malerarbeiten','Bodenbelag','Fenster eingebaut','Türen eingebaut','Dacharbeiten','Gerüstarbeiten','Sonstige Arbeiten'].map(s=>`<button type="button" onclick="addText('f-arb','${s}')" style="padding:4px 10px;background:var(--bg);border:1.5px solid var(--border);color:var(--text-sec);border-radius:6px;font-size:11px;font-weight:500;cursor:pointer;font-family:inherit;transition:all 0.1s" onmouseover="this.style.borderColor='var(--p)';this.style.color='var(--p)'" onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--text-sec)'">${s}</button>`).join('')}</div><textarea id="f-arb" rows="4" placeholder="Welche Arbeiten wurden durchgeführt?"></textarea></div><div class="fg"><label>MÄNGEL</label><textarea id="f-maeng" rows="3" placeholder="Keine Mängel / oder Mängel beschreiben..."></textarea></div><div class="fg"><label>MÄNGEL FRIST</label><input id="f-frist" type="date"></div><div class="fg"><label>BEMERKUNGEN</label><textarea id="f-bem" rows="2" placeholder="Sonstige Bemerkungen..."></textarea></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGNEHMER</label><canvas id="sig-an" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-an')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGGEBER</label><canvas id="sig-ag2" width="400" height="120"></canvas><button type="button" onclick="clearSig('sig-ag2')" style="padding:5px 12px;background:var(--bg);border:1.5px solid var(--border);border-radius:7px;font-size:11px;font-weight:500;cursor:pointer;color:var(--text-sec)">Löschen</button></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAbnahme('${pid}')">Speichern & PDF</button></div>`);initSig('sig-an');initSig('sig-ag2');}
async function saveAbnahme(pid){const arb=document.getElementById('f-arb').value.trim();if(!arb){alert('Erledigte Arbeiten fehlen!');return;}const sigAn=document.getElementById('sig-an').toDataURL();const sigAg=document.getElementById('sig-ag2').toDataURL();const o={projekt_id:pid,datum:heute(),ort:document.getElementById('f-ort').value,auftragnehmer:document.getElementById('f-an').value,auftraggeber:document.getElementById('f-ag').value,arbeiten_erledigt:arb,maengel:document.getElementById('f-maeng').value,maengel_frist:document.getElementById('f-frist').value||null,bemerkungen:document.getElementById('f-bem').value,unterschrift_auftragnehmer:sigAn,unterschrift_auftraggeber:sigAg,erstellt_von:me.email};const{data,error}=await sb.from('abnahmen').insert(o).select().single();if(error){alert('Fehler: '+error.message);return;}cM();exportAbnahmePDF(o);}
function exportAbnahmePDF(a){const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[37,99,235];const grau=[107,114,128];const L=20,R=190,W=170;doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');doc.setFillColor(255,255,255);doc.roundedRect(L-5,12,W+10,38,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,12,W+10,38,3,3,'S');doc.setTextColor(...blau);doc.setFontSize(20);doc.setFont('helvetica','bold');doc.text('ABNAHMEPROTOKOLL',L,28);doc.setFontSize(9);doc.setFont('helvetica','normal');doc.setTextColor(...grau);doc.text(a.auftragnehmer||'',L,36);doc.text(new Date().toLocaleDateString('de-DE'),R,24,'right');doc.text('Ort: '+(a.ort||'-'),R,31,'right');let y=64;doc.setFillColor(255,255,255);doc.roundedRect(L-5,y-6,W+10,22,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,y-6,W+10,22,3,3,'S');doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...grau);doc.text('AUFTRAGNEHMER',L,y);doc.text('AUFTRAGGEBER',L+90,y);doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(11);doc.text(a.auftragnehmer||'-',L,y+9);doc.text(a.auftraggeber||'-',L+90,y+9);y+=30;const sections=[{title:'ERLEDIGTE ARBEITEN',value:a.arbeiten_erledigt},{title:'MAENGEL',value:a.maengel||'Keine Maengel festgestellt'},{title:'BEMERKUNGEN',value:a.bemerkungen}];sections.forEach(s=>{if(!s.value)return;if(y>255){doc.addPage();y=20;}doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text(s.title,L,y);y+=6;doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);const lines=doc.splitTextToSize(s.value,W);lines.forEach(l=>{if(y>270){doc.addPage();y=20;}doc.text(l,L,y);y+=6;});y+=4;});if(a.maengel_frist){doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('FRIST ZUR MANGELBESEITIGUNG',L,y);y+=6;doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);doc.text(fmtDatum(a.maengel_frist),L,y);y+=12;}if(y>190){doc.addPage();y=20;}doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('UNTERSCHRIFTEN',L,y);y+=8;const hasBl=a.unterschrift_auftragnehmer&&a.unterschrift_auftragnehmer.length>100;const hasAg=a.unterschrift_auftraggeber&&a.unterschrift_auftraggeber.length>100;if(hasBl){try{doc.addImage(a.unterschrift_auftragnehmer,'PNG',L,y,75,25);}catch(e){}}if(hasAg){try{doc.addImage(a.unterschrift_auftraggeber,'PNG',L+90,y,75,25);}catch(e){}}doc.setFontSize(8);doc.setTextColor(...grau);doc.text('Auftragnehmer',L+20,y+30);doc.text('Auftraggeber',L+110,y+30);doc.setDrawColor(229,231,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Alem Facility PRO · '+new Date().toLocaleDateString('de-DE'),L,283);doc.save('Abnahmeprotokoll_'+heute()+'.pdf');}
function exportBtPDF(bt,projektName,firmaName){const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[37,99,235];const grau=[107,114,128];const L=20,R=190,W=170;doc.setFillColor(249,250,251);doc.rect(0,0,210,297,'F');doc.setFillColor(255,255,255);doc.roundedRect(L-5,12,W+10,38,3,3,'F');doc.setDrawColor(229,231,235);doc.roundedRect(L-5,12,W+10,38,3,3,'S');doc.setTextColor(...blau);doc.setFontSize(20);doc.setFont('helvetica','bold');doc.text('BAUTAGESPROTOKOLL',L,28);doc.setFontSize(9);doc.setFont('helvetica','normal');doc.setTextColor(...grau);doc.text(firmaName||'',L,36);doc.text('Projekt: '+(projektName||''),R,24,'right');doc.text('Datum: '+fmtDatum(bt.datum),R,31,'right');doc.text('Zeit: '+(bt.zeit_von||'-')+' - '+(bt.zeit_bis||'-')+' Uhr',R,38,'right');let y=64;const sections=[{title:'GEWERK / FIRMA',value:bt.gewerk},{title:'ANWESENDE MITARBEITER',value:bt.mitarbeiter},{title:'DURCHGEFUEHRTE TAETIGKEITEN',value:bt.beschreibung},{title:'VERWENDETES MATERIAL',value:bt.material_verwendet},{title:'LIEFERUNGEN',value:bt.lieferungen},{title:'MAENGEL / BESONDERHEITEN',value:bt.maengel}];sections.forEach(s=>{if(!s.value)return;if(y>255){doc.addPage();y=20;}doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text(s.title,L,y);y+=6;doc.setFont('helvetica','normal');doc.setTextColor(17,24,39);doc.setFontSize(10);const lines=doc.splitTextToSize(s.value,W);lines.forEach(l=>{if(y>270){doc.addPage();y=20;}doc.text(l,L,y);y+=6;});y+=4;});const hasBl=bt.unterschrift_bauleiter&&bt.unterschrift_bauleiter.length>100;const hasAg=bt.unterschrift_auftraggeber&&bt.unterschrift_auftraggeber.length>100;if(hasBl||hasAg){if(y>190){doc.addPage();y=20;}doc.setDrawColor(229,231,235);doc.line(L,y,R,y);y+=8;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('UNTERSCHRIFTEN',L,y);y+=8;if(hasBl&&hasAg){try{doc.addImage(bt.unterschrift_bauleiter,'PNG',L,y,75,25);}catch(e){}try{doc.addImage(bt.unterschrift_auftraggeber,'PNG',L+90,y,75,25);}catch(e){}doc.setFontSize(8);doc.setTextColor(...grau);doc.text('Bauleiter',L+25,y+30);doc.text('Auftraggeber',L+110,y+30);}else if(hasBl){try{doc.addImage(bt.unterschrift_bauleiter,'PNG',L,y,75,25);}catch(e){}doc.setFontSize(8);doc.setTextColor(...grau);doc.text('Bauleiter',L+25,y+30);}else if(hasAg){try{doc.addImage(bt.unterschrift_auftraggeber,'PNG',L,y,75,25);}catch(e){}doc.setFontSize(8);doc.setTextColor(...grau);doc.text('Auftraggeber',L+25,y+30);}}doc.setDrawColor(229,231,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Alem Facility PRO · Erstellt von: '+(bt.erstellt_von||'-'),L,283);doc.save('Bautagesprotokoll_'+fmtDatum(bt.datum||heute())+'.pdf');}
function pgEinst(){sC(`<div class="ph"><div><div class="pt">Einstellungen</div><div class="ps">Firma & App konfigurieren</div></div></div><div class="tc" style="margin-bottom:12px"><div class="th"><span class="th-t">Firmendaten</span></div><div style="padding:16px"><div class="fg"><label>FIRMENNAME</label><input id="s-firma" value="${settings.firma||''}" placeholder="Alem Facility GmbH"></div><div class="fg"><label>ADRESSE</label><input id="s-adr" value="${settings.adresse||''}" placeholder="Musterstr. 1, Berlin"></div><div class="fr"><div class="fg"><label>TELEFON</label><input id="s-tel" value="${settings.telefon||''}" placeholder="+49 ..."></div><div class="fg"><label>E-MAIL</label><input id="s-em" value="${settings.email||''}" placeholder="info@firma.de"></div></div></div></div><div class="tc" style="margin-bottom:12px"><div class="th"><span class="th-t">Rechnungseinstellungen</span></div><div style="padding:16px"><div class="fr"><div class="fg"><label>MWST (%)</label><input id="s-mwst" type="number" value="${settings.mwst||19}"></div><div class="fg"><label>ZAHLUNGSZIEL (TAGE)</label><input id="s-ziel" type="number" value="${settings.zahlungsziel||14}"></div></div><div class="fr"><div class="fg"><label>UST-ID</label><input id="s-ustid" value="${settings.ustid||''}" placeholder="DE123456789"></div><div class="fg"><label>STEUERNUMMER</label><input id="s-steuernr" value="${settings.steuernr||''}" placeholder="123/456/78901"></div></div><div class="fg"><label>IBAN</label><input id="s-iban" value="${settings.iban||''}" placeholder="DE89 3704 0044 0532 0130 00"></div><div class="fg"><label>BANK</label><input id="s-bank" value="${settings.bank||''}" placeholder="Deutsche Bank"></div></div></div><div class="tc" style="margin-bottom:16px"><div class="th"><span class="th-t">Konto</span></div><div style="padding:16px"><div class="fg"><label>E-MAIL</label><input value="${me?.email||''}" disabled style="background:var(--bg);color:var(--text-ter)"></div><div class="fg"><label>BENUTZER-ID</label><input value="${me?.id||''}" disabled style="background:var(--bg);color:var(--text-ter);font-size:11px;font-family:monospace"></div></div></div><button class="bp" style="width:100%;padding:13px;font-size:14px" onclick="saveSettings()">Einstellungen speichern</button>`);}
async function loadAndExportBt(btId,projektName){const{data}=await sb.from('bautagebuch').select('*').eq('id',btId).single();if(data)exportBtPDF(data,projektName,settings.firma||'');}
const BEZIRKE=['Mitte','Charlottenburg','Wilmersdorf','Spandau','Steglitz','Zehlendorf','Tempelhof','Schöneberg','Kreuzberg','Friedrichshain','Lichtenberg','Marzahn','Hellersdorf','Treptow','Köpenick','Neukölln','Reinickendorf','Pankow','Prenzlauer Berg','Weißensee'];
const LEAD_STATUS={'neu':{label:'Neu',cls:'bd-b'},'kontaktiert':{label:'Kontaktiert',cls:'bd-o'},'termin':{label:'Termin vereinbart',cls:'bd-o'},'vor_ort':{label:'Vor-Ort Besuch',cls:'bd-o'},'angebot':{label:'Angebot gesendet',cls:'bd-b'},'gewonnen':{label:'Gewonnen ✓',cls:'bd-g'},'verloren':{label:'Verloren',cls:'bd-r'},'kein_interesse':{label:'Kein Interesse',cls:'bd-gr'}};
async function pgKarte(){if(window._leafletMap){window._leafletMap.remove();window._leafletMap=null;}ld();const{data:leads}=await sb.from('leads').select('*');sC('<div class="ph"><div><div class="pt">Berlin Karte</div><div class="ps">'+(leads||[]).length+' Leads eingetragen</div></div><button class="bp" onclick="mLead()">+ Neuer Lead</button></div><div style="border-radius:var(--radius);overflow:hidden;border:1px solid var(--border);margin-bottom:16px"><div id="berlin-map" style="height:420px;width:100%"></div></div><div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px"><span style="display:flex;align-items:center;gap:4px;font-size:12px;font-weight:600;color:var(--text-sec)"><span style="width:12px;height:12px;border-radius:50%;background:#2563EB;display:inline-block"></span>Neu</span><span style="display:flex;align-items:center;gap:4px;font-size:12px;font-weight:600;color:var(--text-sec)"><span style="width:12px;height:12px;border-radius:50%;background:#D97706;display:inline-block"></span>Kontaktiert</span><span style="display:flex;align-items:center;gap:4px;font-size:12px;font-weight:600;color:var(--text-sec)"><span style="width:12px;height:12px;border-radius:50%;background:#16A34A;display:inline-block"></span>Gewonnen</span><span style="display:flex;align-items:center;gap:4px;font-size:12px;font-weight:600;color:var(--text-sec)"><span style="width:12px;height:12px;border-radius:50%;background:#DC2626;display:inline-block"></span>Verloren</span></div><div class="sh">Leads ohne Koordinaten</div><div id="leads-ohne-coords" class="gr"></div>');setTimeout(()=>{window._leafletMap=L.map('berlin-map').setView([52.52,13.405],11);const map=window._leafletMap;L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'© OpenStreetMap'}).addTo(map);const farben={neu:'#2563EB',kontaktiert:'#D97706',termin:'#D97706',vor_ort:'#D97706',angebot:'#D97706',gewonnen:'#16A34A',verloren:'#DC2626',kein_interesse:'#9CA3AF'};const ohneCoords=[];(leads||[]).forEach(l=>{if(l.adresse){const farbe=farben[l.status]||'#2563EB';const icon=L.divIcon({html:'<div style="width:16px;height:16px;border-radius:50%;background:'+farbe+';border:2px solid #fff;box-shadow:0 1px 4px rgba(0,0,0,0.3)"></div>',iconSize:[16,16],className:''});fetch('https://nominatim.openstreetmap.org/search?format=json&q='+encodeURIComponent(l.adresse+', Berlin')+'&limit=1').then(r=>r.json()).then(data=>{if(data&&data[0]){const marker=L.marker([parseFloat(data[0].lat),parseFloat(data[0].lon)],{icon}).addTo(map);marker.bindPopup('<b>'+l.firma+'</b><br>'+l.adresse+'<br><span style="color:'+farbe+';font-weight:600">'+(LEAD_STATUS[l.status]?.label||l.status)+'</span>');}}).catch(()=>{});}else{ohneCoords.push(l);}});const el=document.getElementById('leads-ohne-coords');if(el){if(!ohneCoords.length){el.innerHTML='<div style="font-size:13px;color:var(--text-ter);padding:8px 0">Alle Leads haben eine Adresse ✓</div>';}else{el.innerHTML=ohneCoords.map(l=>'<div class="ca" onclick="pgLeadDetail(\''+l.id+'\')"><div class="ca-t">'+l.firma+'</div><div class="ca-s">Keine Adresse – tippen zum Bearbeiten</div></div>').join('');}}},300);}
async function pgLeads(){ld();try{const[{data:leads}]=await Promise.all([sb.from('leads').select('*').order('created_at',{ascending:false})]);const heute_leads=(leads||[]).filter(l=>l.naechste_aktion_datum===heute());const gewonnen=(leads||[]).filter(l=>l.status==='gewonnen').length;const inPipeline=(leads||[]).filter(l=>!['gewonnen','verloren','kein_interesse'].includes(l.status)).length;const conversion=(leads||[]).length>0?Math.round((gewonnen/(leads||[]).length)*100):0;sC(`<div class="ph"><div><div class="pt">Akquise</div><div class="ps">${(leads||[]).length} Leads gesamt</div></div><button class="bp" onclick="mLead()">+ Neuer Lead</button></div><div class="sts"><div class="st" onclick="filterLeads('alle')"><div class="si">🎯</div><div class="sv">${(leads||[]).length}</div><div class="sl">Gesamt</div></div><div class="st" onclick="filterLeads('aktiv')"><div class="si">🔄</div><div class="sv">${inPipeline}</div><div class="sl">In Pipeline</div></div><div class="st" onclick="filterLeads('gewonnen')"><div class="si">✅</div><div class="sv" style="color:var(--green)">${gewonnen}</div><div class="sl">Gewonnen</div></div><div class="st"><div class="si">📊</div><div class="sv">${conversion}%</div><div class="sl">Conversion</div></div></div>${heute_leads.length?`<div class="sh">⚡ Heute fällig (${heute_leads.length})</div><div class="tc" style="margin-bottom:16px">${heute_leads.map(l=>`<div style="display:flex;align-items:center;gap:12px;padding:12px 16px;border-bottom:1px solid var(--border-l);cursor:pointer" onclick="pgLeadDetail('${l.id}')"><div style="width:8px;height:8px;border-radius:50%;background:var(--red);flex-shrink:0"></div><div style="flex:1"><div style="font-size:13px;font-weight:700">${l.firma}</div><div style="font-size:12px;color:var(--text-sec)">${l.naechste_aktion||'Aktion fällig'}</div></div><span class="bd ${LEAD_STATUS[l.status]?.cls||'bd-b'}">${LEAD_STATUS[l.status]?.label||l.status}</span></div>`).join('')}</div>`:''}<div style="display:flex;gap:8px;margin-bottom:12px;overflow-x:auto;padding-bottom:4px"><button onclick="filterLeads('alle')" style="padding:6px 14px;background:var(--surface);border:1.5px solid var(--border);border-radius:20px;font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap;font-family:inherit;color:var(--text-sec)">Alle (${(leads||[]).length})</button>${Object.entries(LEAD_STATUS).map(([k,v])=>`<button onclick="filterLeads('${k}')" style="padding:6px 14px;background:var(--surface);border:1.5px solid var(--border);border-radius:20px;font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap;font-family:inherit;color:var(--text-sec)">${v.label} (${(leads||[]).filter(l=>l.status===k).length})</button>`).join('')}</div><div id="leads-liste">${renderLeadsListe(leads||[])}</div>`);}catch(e){sC(`<div class="em"><div class="em-t">Fehler: ${e.message}</div></div>`);}}
function renderLeadsListe(leads){if(!leads.length)return'<div class="em"><div class="em-i">🎯</div><div class="em-t">Noch keine Leads</div><div class="em-s">Füge deinen ersten potentiellen Kunden hinzu</div></div>';return`<div class="gr">${leads.map(l=>`<div class="ca" onclick="pgLeadDetail('${l.id}')"><div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px"><div><div class="ca-t">${l.firma}</div><div class="ca-s">${l.ansprechpartner||''} ${l.telefon?'· '+l.telefon:''}</div></div><span class="bd ${LEAD_STATUS[l.status]?.cls||'bd-b'}">${LEAD_STATUS[l.status]?.label||l.status}</span></div><div style="display:flex;align-items:center;gap:8px;margin-top:6px"><span style="font-size:11px;color:var(--text-ter)">📍 ${l.bezirk||'-'}</span>${l.naechste_aktion_datum?`<span style="font-size:11px;color:${l.naechste_aktion_datum<heute()?'var(--red)':'var(--text-ter)'}">⏰ ${fmtDatum(l.naechste_aktion_datum)}</span>`:''} ${l.zustaendig?`<span style="font-size:11px;color:var(--text-ter)">👤 ${l.zustaendig}</span>`:''}</div></div>`).join('')}</div>`;}
async function filterLeads(filter){const{data:leads}=await sb.from('leads').select('*').order('created_at',{ascending:false});let filtered=leads||[];if(filter==='aktiv')filtered=filtered.filter(l=>!['gewonnen','verloren','kein_interesse'].includes(l.status));else if(filter==='gewonnen')filtered=filtered.filter(l=>l.status==='gewonnen');else if(filter!=='alle')filtered=filtered.filter(l=>l.status===filter);document.getElementById('leads-liste').innerHTML=renderLeadsListe(filtered);}
async function pgLeadDetail(id){ld();const{data:l}=await sb.from('leads').select('*').eq('id',id).single();const{data:logs}=await sb.from('anruf_log').select('*').eq('lead_id',id).order('created_at',{ascending:false});if(!l){sC('<div class="em"><div class="em-t">Lead nicht gefunden</div></div>');return;}sC(`<button class="bk" onclick="pgLeads()">← Zurück</button><div class="ph"><div><div class="pt">${l.firma}</div><div class="ps">${l.bezirk||''} ${l.ansprechpartner?'· '+l.ansprechpartner:''}</div></div><button class="bp" onclick='mLead(${JSON.stringify(l).replace(/'/g,"&#39;")})' style="background:var(--bg);color:var(--text);border:1px solid var(--border)">Bearbeiten</button></div><div class="info-grid"><div class="info-box"><div class="info-label">Status</div><div class="info-val"><span class="bd ${LEAD_STATUS[l.status]?.cls||'bd-b'}">${LEAD_STATUS[l.status]?.label||l.status}</span></div></div><div class="info-box"><div class="info-label">Bezirk</div><div class="info-val">📍 ${l.bezirk||'-'}</div></div><div class="info-box"><div class="info-label">Zuständig</div><div class="info-val">👤 ${l.zustaendig||'-'}</div></div><div class="info-box"><div class="info-label">Quelle</div><div class="info-val">${l.quelle||'-'}</div></div></div>${l.telefon?`<a href="tel:${l.telefon}" style="display:flex;align-items:center;gap:10px;background:var(--green-bg);border:1px solid var(--green);border-radius:var(--radius);padding:14px 16px;margin-bottom:12px;text-decoration:none"><span style="font-size:20px">📞</span><div><div style="font-size:13px;font-weight:700;color:var(--green)">Jetzt anrufen</div><div style="font-size:12px;color:var(--text-sec)">${l.telefon}</div></div></a>`:''} ${l.email?`<a href="mailto:${l.email}" style="display:flex;align-items:center;gap:10px;background:var(--p-light);border:1px solid var(--p);border-radius:var(--radius);padding:14px 16px;margin-bottom:12px;text-decoration:none"><span style="font-size:20px">✉️</span><div><div style="font-size:13px;font-weight:700;color:var(--p)">E-Mail senden</div><div style="font-size:12px;color:var(--text-sec)">${l.email}</div></div></a>`:''} ${l.naechste_aktion?`<div style="background:var(--yellow-bg);border:1px solid var(--yellow);border-radius:var(--radius);padding:12px 16px;margin-bottom:12px"><div style="font-size:11px;font-weight:700;color:var(--yellow);margin-bottom:4px">NÄCHSTE AKTION</div><div style="font-size:13px;font-weight:600">${l.naechste_aktion}</div>${l.naechste_aktion_datum?`<div style="font-size:12px;color:var(--text-sec);margin-top:2px">📅 ${fmtDatum(l.naechste_aktion_datum)}</div>`:''}</div>`:''} ${l.notiz?`<div class="tc" style="margin-bottom:12px"><div class="th"><span class="th-t">📝 Notizen</span></div><div style="padding:14px;font-size:13px;color:var(--text-sec);line-height:1.6">${l.notiz}</div></div>`:''}<div class="sh">Anruf-Log</div><div class="tc" style="margin-bottom:12px"><div class="th"><span class="th-t">Gespräche</span><button class="bp" style="padding:6px 12px;font-size:12px" onclick="mAnrufLog('${id}')">+ Anruf</button></div>${!(logs&&logs.length)?'<div style="padding:20px;text-align:center;color:var(--text-ter);font-size:13px">Noch keine Anrufe</div>':logs.map(log=>`<div style="padding:12px 16px;border-bottom:1px solid var(--border-l)"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-size:12px;font-weight:700;color:var(--text)">${log.ergebnis||'-'}</span><span style="font-size:11px;color:var(--text-ter)">${fmtDatum(log.datum)} ${log.uhrzeit||''}</span></div>${log.notiz?`<div style="font-size:12px;color:var(--text-sec)">${log.notiz}</div>`:''}</div>`).join('')}</div>`);}
function mAnrufLog(leadId){oM(`${modalHeader('Anruf erfassen')}<div class="fg"><label>ERGEBNIS</label><select id="f-erg"><option value="Nicht erreicht">Nicht erreicht</option><option value="Interessiert">Interessiert</option><option value="Rückruf gewünscht">Rückruf gewünscht</option><option value="Termin vereinbart">Termin vereinbart</option><option value="Kein Interesse">Kein Interesse</option><option value="Angebot angefordert">Angebot angefordert</option></select></div><div class="fr"><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>UHRZEIT</label><input id="f-u" type="time" value="${new Date().toTimeString().slice(0,5)}"></div></div><div class="fg"><label>NOTIZ</label><textarea id="f-not" rows="3" placeholder="Was wurde besprochen?"></textarea></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAnrufLog('${leadId}')">Speichern</button></div>`);}
async function saveAnrufLog(leadId){const erg=document.getElementById('f-erg').value;const{error}=await sb.from('anruf_log').insert({lead_id:leadId,datum:document.getElementById('f-d').value,uhrzeit:document.getElementById('f-u').value,ergebnis:erg,notiz:document.getElementById('f-not').value,user_id:me.id});if(error){alert('Fehler: '+error.message);return;}if(erg==='Termin vereinbart')await sb.from('leads').update({status:'termin'}).eq('id',leadId);else if(erg==='Interessiert')await sb.from('leads').update({status:'kontaktiert'}).eq('id',leadId);else if(erg==='Kein Interesse')await sb.from('leads').update({status:'kein_interesse'}).eq('id',leadId);cM();pgLeadDetail(leadId);}
function mLead(l={}){const mitOpts=[{name:'Ich'},{name:'Mitarbeiter'},..._mitarbeiter].map(m=>`<option value="${m.name}"${l.zustaendig===m.name?' selected':''}>${m.name}</option>`).join('');oM(`${modalHeader(l.id?'Lead bearbeiten':'Neuer Lead')}<div style="background:var(--yellow-bg);border:1px solid var(--yellow);border-radius:10px;padding:10px 14px;margin-bottom:16px;font-size:12px;color:var(--yellow);font-weight:600">⚖️ Nur B2B – Firmenkunden. Privatpersonen nicht eintragen (UWG).</div><div class="fg"><label>FIRMENNAME *</label><input id="f-firma" value="${l.firma||''}" placeholder="Müller Immobilien GmbH"></div><div class="fr"><div class="fg"><label>ANSPRECHPARTNER</label><input id="f-ap" value="${l.ansprechpartner||''}" placeholder="Hr. Müller"></div><div class="fg"><label>TELEFON</label><input id="f-tel" value="${l.telefon||''}" placeholder="+49 30 ..."></div></div><div class="fr"><div class="fg"><label>E-MAIL</label><input id="f-em" value="${l.email||''}" placeholder="info@firma.de"></div><div class="fg"><label>BEZIRK</label><select id="f-bez">${BEZIRKE.map(b=>`<option value="${b}"${(l.bezirk||'Mitte')===b?' selected':''}>${b}</option>`).join('')}</select></div></div><div class="fg"><label>ADRESSE</label><input id="f-adr" value="${l.adresse||''}" placeholder="Musterstr. 1, Berlin"></div><div class="fr"><div class="fg"><label>STATUS</label><select id="f-st">${Object.entries(LEAD_STATUS).map(([k,v])=>`<option value="${k}"${(l.status||'neu')===k?' selected':''}>${v.label}</option>`).join('')}</select></div><div class="fg"><label>ZUSTÄNDIG</label><select id="f-zu">${mitOpts}</select></div></div><div class="fg"><label>QUELLE</label><select id="f-qu"><option value="Kaltakquise"${l.quelle==='Kaltakquise'?' selected':''}>Kaltakquise</option><option value="Empfehlung"${l.quelle==='Empfehlung'?' selected':''}>Empfehlung</option><option value="Google"${l.quelle==='Google'?' selected':''}>Google</option><option value="Messe"${l.quelle==='Messe'?' selected':''}>Messe</option><option value="Sonstiges"${l.quelle==='Sonstiges'?' selected':''}>Sonstiges</option></select></div><div class="fr"><div class="fg"><label>NÄCHSTE AKTION</label><input id="f-na" value="${l.naechste_aktion||''}" placeholder="Anrufen / Termin / Angebot"></div><div class="fg"><label>FÄLLIG AM</label><input id="f-nad" type="date" value="${l.naechste_aktion_datum||''}"></div></div><div class="fg"><label>NOTIZ</label><textarea id="f-not" rows="3" placeholder="Gesprächsnotizen...">${l.notiz||''}</textarea></div><div class="fg" style="background:var(--bg);border-radius:10px;padding:12px"><label style="display:flex;align-items:center;gap:10px;cursor:pointer"><button type="button" id="f-einw" onclick="this.dataset.checked=this.dataset.checked==='1'?'0':'1';this.style.background=this.dataset.checked==='1'?'var(--green)':'var(--border)';this.style.borderColor=this.dataset.checked==='1'?'var(--green)':'var(--border)';this.textContent=this.dataset.checked==='1'?'✓':'';" data-checked="${l.einwilligung?'1':'0'}" style="width:24px;height:24px;border-radius:6px;border:2px solid ${l.einwilligung?'var(--green)':'var(--border)'};background:${l.einwilligung?'var(--green)':'transparent'};color:#fff;font-size:14px;cursor:pointer;flex-shrink:0">${l.einwilligung?'✓':''}</button><span style="font-size:12px;font-weight:600;color:var(--text-sec)">Firma hat Kontaktaufnahme zugestimmt (DSGVO)</span></label></div><div class="ma">${l.id?`<button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delLead('${l.id}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveLead('${l.id||''}')">Speichern</button></div>`);}
async function saveLead(id){const firma=document.getElementById('f-firma').value.trim();if(!firma){alert('Firmenname fehlt!');return;}const einw=document.getElementById('f-einw').dataset.checked==='1';const o={firma,ansprechpartner:document.getElementById('f-ap').value,telefon:document.getElementById('f-tel').value,email:document.getElementById('f-em').value,adresse:document.getElementById('f-adr').value,bezirk:document.getElementById('f-bez').value,status:document.getElementById('f-st').value,zustaendig:document.getElementById('f-zu').value,quelle:document.getElementById('f-qu').value,naechste_aktion:document.getElementById('f-na').value,naechste_aktion_datum:document.getElementById('f-nad').value||null,notiz:document.getElementById('f-not').value,einwilligung:einw,einwilligung_datum:einw?heute():null,user_id:me.id};const{error}=id?await sb.from('leads').update(o).eq('id',id):await sb.from('leads').insert(o);if(error){alert('Fehler: '+error.message);return;}document.getElementById('mo').classList.remove('open');pgLeads();}
async function delLead(id){if(!confirm('Lead wirklich löschen?'))return;await sb.from('leads').delete().eq('id',id);cM();pgLeads();}
async function pgAufgaben(){ld();try{const[{data:auf},{data:proj},{data:leads}]=await Promise.all([sb.from('aufgaben').select('*').order('faellig',{ascending:true}),sb.from('projekte').select('id,name'),sb.from('leads').select('id,firma')]);const offen=(auf||[]).filter(a=>a.status==='offen');const erledigt=(auf||[]).filter(a=>a.status==='erledigt');const heute_auf=offen.filter(a=>a.faellig===heute());const ueberfaellig=offen.filter(a=>a.faellig&&a.faellig<heute());sC(`<div class="ph"><div><div class="pt">Aufgaben</div><div class="ps">${offen.length} offen · ${erledigt.length} erledigt</div></div><button class="bp" onclick='mAufgabe(${JSON.stringify(proj||[]).replace(/'/g,"&#39;")},${JSON.stringify(leads||[]).replace(/'/g,"&#39;")})'>+ Neue Aufgabe</button></div>${ueberfaellig.length?`<div style="background:var(--red-bg);border:1px solid var(--red);border-radius:var(--radius);padding:12px 16px;margin-bottom:12px"><div style="font-size:12px;font-weight:700;color:var(--red);margin-bottom:6px">⚠️ ÜBERFÄLLIG (${ueberfaellig.length})</div>${ueberfaellig.map(a=>`<div style="display:flex;align-items:center;gap:10px;padding:6px 0;border-bottom:1px solid rgba(220,38,38,0.2)" onclick="mAufgabeEdit(${JSON.stringify(a).replace(/'/g,'&#39;')},${JSON.stringify(proj||[]).replace(/'/g,'&#39;')},${JSON.stringify(leads||[]).replace(/'/g,'&#39;')})"><div style="flex:1"><div style="font-size:13px;font-weight:600;color:var(--text)">${a.titel}</div><div style="font-size:11px;color:var(--red)">${fmtDatum(a.faellig)} · ${a.zustaendig||'Ich'}</div></div><button onclick="event.stopPropagation();erledigeAufgabe('${a.id}')" style="padding:4px 10px;background:var(--green);color:#fff;border:none;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer">✓</button></div>`).join('')}</div>`:''} ${heute_auf.length?`<div style="background:var(--yellow-bg);border:1px solid var(--yellow);border-radius:var(--radius);padding:12px 16px;margin-bottom:12px"><div style="font-size:12px;font-weight:700;color:var(--yellow);margin-bottom:6px">📅 HEUTE (${heute_auf.length})</div>${heute_auf.map(a=>`<div style="display:flex;align-items:center;gap:10px;padding:6px 0;border-bottom:1px solid rgba(217,119,6,0.2)" onclick="mAufgabeEdit(${JSON.stringify(a).replace(/'/g,'&#39;')},${JSON.stringify(proj||[]).replace(/'/g,'&#39;')},${JSON.stringify(leads||[]).replace(/'/g,'&#39;')})"><div style="flex:1"><div style="font-size:13px;font-weight:600;color:var(--text)">${a.titel}</div><div style="font-size:11px;color:var(--yellow)">${a.zustaendig||'Ich'} · Priorität ${a.prioritaet||'B'}</div></div><button onclick="event.stopPropagation();erledigeAufgabe('${a.id}')" style="padding:4px 10px;background:var(--green);color:#fff;border:none;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer">✓</button></div>`).join('')}</div>`:''}<div class="sh">Alle offenen Aufgaben (${offen.length})</div><div class="gr">${!offen.length?'<div class="em"><div class="em-i">✅</div><div class="em-t">Keine offenen Aufgaben</div></div>':offen.map(a=>`<div class="ca" onclick='mAufgabeEdit(${JSON.stringify(a).replace(/'/g,"&#39;")},${JSON.stringify(proj||[]).replace(/'/g,"&#39;")},${JSON.stringify(leads||[]).replace(/'/g,"&#39;")})' style="cursor:pointer"><div style="display:flex;justify-content:space-between;align-items:flex-start"><div style="flex:1"><div style="display:flex;align-items:center;gap:8px;margin-bottom:4px"><span style="width:8px;height:8px;border-radius:50%;background:${a.prioritaet==='A'?'var(--red)':a.prioritaet==='B'?'var(--yellow)':'var(--green)'};flex-shrink:0"></span><div class="ca-t">${a.titel}</div></div><div class="ca-s">${a.zustaendig||'Ich'} ${a.faellig?'· '+fmtDatum(a.faellig):''} ${a.prioritaet?'· Prio '+a.prioritaet:''}</div></div><button onclick="event.stopPropagation();erledigeAufgabe('${a.id}')" style="padding:6px 12px;background:var(--green);color:#fff;border:none;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;flex-shrink:0">✓</button></div></div>`).join('')}</div>${erledigt.length?`<div class="sh">Erledigt (${erledigt.length})</div><div class="gr">${erledigt.slice(0,5).map(a=>`<div class="ca" style="opacity:0.6"><div style="display:flex;align-items:center;gap:8px"><span style="font-size:16px">✅</span><div><div style="font-size:13px;font-weight:600;color:var(--text);text-decoration:line-through">${a.titel}</div><div style="font-size:12px;color:var(--text-ter)">${a.zustaendig||'Ich'}</div></div></div></div>`).join('')}</div>`:''}`);}catch(e){sC(`<div class="em"><div class="em-t">Fehler: ${e.message}</div></div>`);}}
function mAufgabe(proj,leads){const mitOpts=[{name:'Ich'},{name:'Mitarbeiter'},..._mitarbeiter].map(m=>`<option value="${m.name}">${m.name}</option>`).join('');oM(`${modalHeader('Neue Aufgabe')}<div class="fg"><label>TITEL *</label><input id="f-t" placeholder="z.B. Müller GmbH anrufen"></div><div class="fg"><label>BESCHREIBUNG</label><textarea id="f-b" rows="2" placeholder="Details..."></textarea></div><div class="fr"><div class="fg"><label>PRIORITÄT</label><select id="f-p"><option value="A">A – Muss heute</option><option value="B" selected>B – Sollte heute</option><option value="C">C – Irgendwann</option></select></div><div class="fg"><label>ZUSTÄNDIG</label><select id="f-zu">${mitOpts}</select></div></div><div class="fg"><label>FÄLLIG AM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>PROJEKT</label><select id="f-proj"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>LEAD</label><select id="f-lead"><option value="">- Kein Lead -</option>${(leads||[]).map(l=>`<option value="${l.id}">${l.firma}</option>`).join('')}</select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAufgabe('')">Speichern</button></div>`);}
function mAufgabeEdit(a,proj,leads){const mitOpts=[{name:'Ich'},{name:'Mitarbeiter'},..._mitarbeiter].map(m=>`<option value="${m.name}"${a.zustaendig===m.name?' selected':''}>${m.name}</option>`).join('');oM(`${modalHeader('Aufgabe bearbeiten')}<div class="fg"><label>TITEL *</label><input id="f-t" value="${a.titel||''}"></div><div class="fg"><label>BESCHREIBUNG</label><textarea id="f-b" rows="2">${a.beschreibung||''}</textarea></div><div class="fr"><div class="fg"><label>PRIORITÄT</label><select id="f-p"><option value="A"${a.prioritaet==='A'?' selected':''}>A – Muss heute</option><option value="B"${a.prioritaet==='B'?' selected':''}>B – Sollte heute</option><option value="C"${a.prioritaet==='C'?' selected':''}>C – Irgendwann</option></select></div><div class="fg"><label>ZUSTÄNDIG</label><select id="f-zu">${mitOpts}</select></div></div><div class="fg"><label>FÄLLIG AM</label><input id="f-d" type="date" value="${a.faellig||''}"></div><div class="fg"><label>PROJEKT</label><select id="f-proj"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===a.projekt_id?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>LEAD</label><select id="f-lead"><option value="">- Kein Lead -</option>${(leads||[]).map(l=>`<option value="${l.id}"${l.id===a.lead_id?' selected':''}>${l.firma}</option>`).join('')}</select></div><div class="ma"><button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delAufgabe('${a.id}')">Löschen</button><button class="bs" onclick="saveAufgabe('${a.id}')">Speichern</button></div>`);}
async function saveAufgabe(id){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const o={titel:t,beschreibung:document.getElementById('f-b').value,prioritaet:document.getElementById('f-p').value,zustaendig:document.getElementById('f-zu').value,faellig:document.getElementById('f-d').value||null,projekt_id:document.getElementById('f-proj').value||null,lead_id:document.getElementById('f-lead').value||null,status:'offen',user_id:me.id};const{error}=id?await sb.from('aufgaben').update(o).eq('id',id):await sb.from('aufgaben').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgAufgaben();}
async function erledigeAufgabe(id){await sb.from('aufgaben').update({status:'erledigt'}).eq('id',id);pgAufgaben();}
async function delAufgabe(id){if(!confirm('Aufgabe löschen?'))return;await sb.from('aufgaben').delete().eq('id',id);cM();pgAufgaben();}
// ─── KALKULATION ────────────────────────────────────────────────
const DEFAULT_PRESETS=[{name:'Maler',einheit:'m²',arbeitspreis:8,materialpreis:4,verschnitt:10,marge:25,stundensatz:45},{name:'Fliesen',einheit:'m²',arbeitspreis:35,materialpreis:25,verschnitt:15,marge:25,stundensatz:55},{name:'Trockenbau',einheit:'m²',arbeitspreis:22,materialpreis:12,verschnitt:10,marge:20,stundensatz:45},{name:'Boden (Laminat)',einheit:'m²',arbeitspreis:12,materialpreis:18,verschnitt:10,marge:20,stundensatz:45},{name:'Abriss',einheit:'m²',arbeitspreis:15,materialpreis:2,verschnitt:0,marge:20,stundensatz:45},{name:'Reinigung',einheit:'m²',arbeitspreis:3.5,materialpreis:0.5,verschnitt:0,marge:20,stundensatz:18},{name:'Hausmeister',einheit:'Std',arbeitspreis:35,materialpreis:5,verschnitt:0,marge:20,stundensatz:35},{name:'Winterdienst',einheit:'m²',arbeitspreis:2.5,materialpreis:1,verschnitt:0,marge:20,stundensatz:25}];
let _presets=[];
async function loadPresets(){try{const{data}=await sb.from('kalk_presets').select('*').order('name');if(data&&data.length)_presets=data;else{_presets=DEFAULT_PRESETS;}}catch(e){_presets=DEFAULT_PRESETS;}}
async function pgKalk(){ld();await loadPresets();try{const{data}=await sb.from('kalkulationen').select('*').order('created_at',{ascending:false});sC(`<div class="ph"><div><div class="pt">Kalkulation</div><div class="ps">${(data||[]).length} Kalkulationen</div></div><button class="bp" onclick="mKalkNeu()">+ Neue Kalkulation</button></div>${!(data&&data.length)?'<div class="em"><div class="em-i">🧮</div><div class="em-t">Noch keine Kalkulationen</div><div class="em-s">Erstelle deine erste Kalkulation</div></div>':`<div class="gr">${data.map(k=>`<div class="ca" onclick="pgKalkDetail('${k.id}')"><div style="display:flex;justify-content:space-between;align-items:flex-start"><div><div class="ca-t">${k.name}</div><div class="ca-s">${k.kunde||'Kein Kunde'}</div></div><span class="bd ${k.status==='angebot'?'bd-g':k.status==='abgeschlossen'?'bd-gr':'bd-b'}">${k.status||'offen'}</span></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-t">Fehler: ${e.message}</div></div>`);}}
function mKalkNeu(){oM(`${modalHeader('Neue Kalkulation')}<div class="fg"><label>PROJEKTNAME *</label><input id="k-name" placeholder="z.B. Renovierung Musterstr."></div><div class="fg"><label>KUNDE</label><input id="k-kunde" placeholder="Müller GmbH"></div><div class="fr"><div class="fg"><label>STANDARD-MARGE (%)</label><input id="k-marge" type="number" value="20"></div><div class="fg"><label>ANFAHRT (€)</label><input id="k-anfahrt" type="number" value="0"></div></div><div class="fg" style="background:var(--bg);border-radius:10px;padding:12px"><label style="font-size:11px;font-weight:700;color:var(--text-ter)">ZUSCHLÄGE</label><div style="display:flex;gap:8px;margin-top:8px;flex-wrap:wrap"><button type="button" id="z-klein" onclick="this.dataset.on=this.dataset.on==='1'?'0':'1';this.style.background=this.dataset.on==='1'?'var(--p)':'var(--bg)';this.style.color=this.dataset.on==='1'?'#fff':'var(--text-sec)'" data-on="0" style="padding:6px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;background:var(--bg);color:var(--text-sec)">Kleinmaterial +5%</button><button type="button" id="z-risiko" onclick="this.dataset.on=this.dataset.on==='1'?'0':'1';this.style.background=this.dataset.on==='1'?'var(--p)':'var(--bg)';this.style.color=this.dataset.on==='1'?'#fff':'var(--text-sec)'" data-on="0" style="padding:6px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;background:var(--bg);color:var(--text-sec)">Risiko +3%</button></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveKalkNeu()">Erstellen</button></div>`);}
async function saveKalkNeu(){const name=document.getElementById('k-name').value.trim();if(!name){alert('Name fehlt!');return;}const{data,error}=await sb.from('kalkulationen').insert({name,kunde:document.getElementById('k-kunde').value,marge_gesamt:parseFloat(document.getElementById('k-marge').value)||20,zuschlag_kleinmaterial:document.getElementById('z-klein').dataset.on==='1',zuschlag_anfahrt:parseFloat(document.getElementById('k-anfahrt').value)||0,zuschlag_risiko:document.getElementById('z-risiko').dataset.on==='1',user_id:me.id}).select().single();if(error){alert('Fehler: '+error.message);return;}cM();pgKalkDetail(data.id);}
async function pgKalkDetail(id){ld();await loadPresets();const[{data:k},{data:pos}]=await Promise.all([sb.from('kalkulationen').select('*').eq('id',id).single(),sb.from('kalk_positionen').select('*').eq('kalkulation_id',id).order('sort_order')]);if(!k)return;const positionen=pos||[];let gesamtNetto=0,gesamtGewinn=0;positionen.forEach(p=>{const mat=(p.menge||0)*(p.materialpreis||0)*(1+(p.verschnitt||0)/100);const arb=p.stunden>0?(p.stunden||0)*(p.stundensatz||0):(p.menge||0)*(p.arbeitspreis||0);const basis=mat+arb;const vk=basis*(1+(p.marge||20)/100);gesamtNetto+=basis;gesamtGewinn+=vk-basis;});const gesamtVK=gesamtNetto+gesamtGewinn;const zuschlagKlein=k.zuschlag_kleinmaterial?gesamtVK*0.05:0;const zuschlagRisiko=k.zuschlag_risiko?gesamtVK*0.03:0;const anfahrt=parseFloat(k.zuschlag_anfahrt)||0;const total=gesamtVK+zuschlagKlein+zuschlagRisiko+anfahrt;const marge=total>0?((gesamtGewinn/total)*100).toFixed(1):0;sC(`<button class="bk" onclick="pgKalk()">← Zurück</button><div class="ph"><div><div class="pt">${k.name}</div><div class="ps">${k.kunde||''}</div></div><button class="bp" onclick="kalkZuAngebot('${id}')" style="background:var(--green)">→ Angebot</button></div><div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:16px"><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:12px;text-align:center"><div style="font-size:11px;font-weight:700;color:var(--text-ter);margin-bottom:4px">VERKAUFSPREIS</div><div style="font-size:20px;font-weight:800;color:var(--p)">${fmtEur(total)}</div></div><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:12px;text-align:center"><div style="font-size:11px;font-weight:700;color:var(--text-ter);margin-bottom:4px">GEWINN</div><div style="font-size:20px;font-weight:800;color:var(--green)">${fmtEur(gesamtGewinn)}</div></div><div style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:12px;text-align:center"><div style="font-size:11px;font-weight:700;color:var(--text-ter);margin-bottom:4px">MARGE</div><div style="font-size:20px;font-weight:800;color:var(--yellow)">${marge}%</div></div></div>${zuschlagKlein||zuschlagRisiko||anfahrt?`<div style="background:var(--bg);border-radius:var(--radius);padding:10px 14px;margin-bottom:12px;font-size:12px;color:var(--text-sec)">${zuschlagKlein?`<div>Kleinmaterial: +${fmtEur(zuschlagKlein)}</div>`:''} ${zuschlagRisiko?`<div>Risiko: +${fmtEur(zuschlagRisiko)}</div>`:''} ${anfahrt?`<div>Anfahrt: +${fmtEur(anfahrt)}</div>`:''}</div>`:''}<div class="sh">Positionen (${positionen.length})</div><div style="margin-bottom:12px">${!positionen.length?'<div class="em"><div class="em-t">Noch keine Positionen</div></div>':positionen.map(p=>{const mat=(p.menge||0)*(p.materialpreis||0)*(1+(p.verschnitt||0)/100);const arb=p.stunden>0?(p.stunden||0)*(p.stundensatz||0):(p.menge||0)*(p.arbeitspreis||0);const basis=mat+arb;const vk=basis*(1+(p.marge||20)/100);return`<div class="ca" style="margin-bottom:8px" onclick="mKalkPos('${id}',${JSON.stringify(p).replace(/'/g,'&#39;')})"><div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px"><div style="font-size:14px;font-weight:700;color:var(--text)">${p.bezeichnung}</div><div style="font-size:14px;font-weight:800;color:var(--p)">${fmtEur(vk)}</div></div><div style="display:flex;gap:12px;font-size:12px;color:var(--text-sec)"><span>${p.menge} ${p.einheit}</span><span>Arbeit: ${fmtEur(arb)}</span><span>Material: ${fmtEur(mat)}</span><span style="color:var(--green)">Marge: ${p.marge||20}%</span></div><div style="display:flex;gap:6px;margin-top:8px"><button onclick="event.stopPropagation();duplizierePos('${id}','${p.id}')" style="padding:4px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;font-size:11px;cursor:pointer;color:var(--text-sec)">Duplizieren</button><button onclick="event.stopPropagation();delKalkPos('${p.id}','${id}')" style="padding:4px 10px;background:var(--bg);border:1px solid var(--red);border-radius:6px;font-size:11px;cursor:pointer;color:var(--red)">Löschen</button></div></div>`;}).join('')}</div><button class="bp" style="width:100%;padding:14px;font-size:14px;margin-bottom:8px" onclick="mKalkPos('${id}',null)">+ Position hinzufügen</button><button onclick="mKalkGlobalMarge('${id}',${k.marge_gesamt||20})" style="width:100%;padding:10px;background:var(--bg);border:1.5px solid var(--border);border-radius:var(--radius);font-size:13px;font-weight:600;cursor:pointer;color:var(--text-sec)">⚙️ Globale Marge anpassen</button>`);}
async function mKalkPos(kalkId,p){await loadPresets();const isEdit=p&&p.id;const presetOpts=_presets.map(pr=>`<option value="${pr.name}">${pr.name} (${fmtEur(pr.arbeitspreis)}/${pr.einheit})</option>`).join('');oM(`${modalHeader(isEdit?'Position bearbeiten':'Neue Position')}<div class="fg"><label>PRESET LADEN</label><select id="k-preset" onchange="ladePreset(this.value)"><option value="">— Preset wählen —</option>${presetOpts}</select></div><div class="fg"><label>BEZEICHNUNG *</label><input id="k-bez" value="${isEdit?p.bezeichnung:''}" placeholder="z.B. Malerarbeiten Wohnzimmer"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="k-menge" type="number" value="${isEdit?p.menge:1}" oninput="kalkLive()"></div><div class="fg"><label>EINHEIT</label><select id="k-einheit"><option value="m²" ${(!isEdit||p.einheit==='m²')?'selected':''}>m²</option><option value="Std" ${isEdit&&p.einheit==='Std'?'selected':''}>Std</option><option value="lfm" ${isEdit&&p.einheit==='lfm'?'selected':''}>lfm</option><option value="Stk" ${isEdit&&p.einheit==='Stk'?'selected':''}>Stk</option><option value="pauschal" ${isEdit&&p.einheit==='pauschal'?'selected':''}>pauschal</option></select></div></div><div class="fr"><div class="fg"><label>ARBEIT (€/Einheit)</label><input id="k-arbeit" type="number" step="0.5" value="${isEdit?p.arbeitspreis:0}" oninput="kalkLive()"></div><div class="fg"><label>MATERIAL (€/Einheit)</label><input id="k-mat" type="number" step="0.5" value="${isEdit?p.materialpreis:0}" oninput="kalkLive()"></div></div><div class="fr"><div class="fg"><label>VERSCHNITT (%)</label><input id="k-verschnitt" type="number" value="${isEdit?p.verschnitt:5}" oninput="kalkLive()"></div><div class="fg"><label>MARGE (%)</label><input id="k-marge" type="number" value="${isEdit?p.marge:20}" oninput="kalkLive()"></div></div><div style="background:var(--p-light);border-radius:10px;padding:12px;margin-bottom:12px"><div style="font-size:11px;font-weight:700;color:var(--text-ter);margin-bottom:6px">DETAIL-MODUS (optional)</div><div class="fr"><div class="fg"><label>STUNDEN</label><input id="k-std" type="number" step="0.5" value="${isEdit?p.stunden:0}" oninput="kalkLive()"></div><div class="fg"><label>STUNDENSATZ</label><input id="k-satz" type="number" step="0.5" value="${isEdit?p.stundensatz:45}" oninput="kalkLive()"></div></div></div><div id="kalk-live" style="background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:12px;margin-bottom:12px"></div><div class="ma">${isEdit?`<button class="bc" style="color:var(--red);border-color:var(--red)" onclick="delKalkPos('${p.id}','${kalkId}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveKalkPos('${kalkId}','${isEdit?p.id:''}')">Speichern</button></div>`);kalkLive();}
function ladePreset(name){const pr=_presets.find(p=>p.name===name);if(!pr)return;document.getElementById('k-arbeit').value=pr.arbeitspreis;document.getElementById('k-mat').value=pr.materialpreis;document.getElementById('k-verschnitt').value=pr.verschnitt;document.getElementById('k-marge').value=pr.marge;document.getElementById('k-satz').value=pr.stundensatz;if(!document.getElementById('k-bez').value)document.getElementById('k-bez').value=pr.name;kalkLive();}
function kalkLive(){const menge=parseFloat(document.getElementById('k-menge')?.value)||0;const arbeit=parseFloat(document.getElementById('k-arbeit')?.value)||0;const mat=parseFloat(document.getElementById('k-mat')?.value)||0;const verschnitt=parseFloat(document.getElementById('k-verschnitt')?.value)||0;const marge=parseFloat(document.getElementById('k-marge')?.value)||0;const std=parseFloat(document.getElementById('k-std')?.value)||0;const satz=parseFloat(document.getElementById('k-satz')?.value)||0;const matGes=menge*mat*(1+verschnitt/100);const arbGes=std>0?std*satz:menge*arbeit;const basis=matGes+arbGes;const vk=basis*(1+marge/100);const gewinn=vk-basis;const el=document.getElementById('kalk-live');if(el)el.innerHTML=`<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px"><div style="text-align:center"><div style="font-size:10px;color:var(--text-ter);font-weight:700">MATERIAL</div><div style="font-size:16px;font-weight:800;color:var(--text)">${fmtEur(matGes)}</div></div><div style="text-align:center"><div style="font-size:10px;color:var(--text-ter);font-weight:700">ARBEIT</div><div style="font-size:16px;font-weight:800;color:var(--text)">${fmtEur(arbGes)}</div></div><div style="text-align:center"><div style="font-size:10px;color:var(--text-ter);font-weight:700">VERKAUF</div><div style="font-size:16px;font-weight:800;color:var(--p)">${fmtEur(vk)}</div></div></div><div style="text-align:center;margin-top:8px;font-size:12px;color:var(--green);font-weight:600">Gewinn: ${fmtEur(gewinn)} · Marge: ${marge}%</div>`;}
async function saveKalkPos(kalkId,posId){const bez=document.getElementById('k-bez').value.trim();if(!bez){alert('Bezeichnung fehlt!');return;}const o={kalkulation_id:kalkId,bezeichnung:bez,menge:parseFloat(document.getElementById('k-menge').value)||1,einheit:document.getElementById('k-einheit').value,arbeitspreis:parseFloat(document.getElementById('k-arbeit').value)||0,materialpreis:parseFloat(document.getElementById('k-mat').value)||0,verschnitt:parseFloat(document.getElementById('k-verschnitt').value)||0,marge:parseFloat(document.getElementById('k-marge').value)||20,stunden:parseFloat(document.getElementById('k-std').value)||0,stundensatz:parseFloat(document.getElementById('k-satz').value)||0,user_id:me.id};const{error}=posId?await sb.from('kalk_positionen').update(o).eq('id',posId):await sb.from('kalk_positionen').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgKalkDetail(kalkId);}
async function delKalkPos(posId,kalkId){if(!confirm('Position löschen?'))return;await sb.from('kalk_positionen').delete().eq('id',posId);cM();pgKalkDetail(kalkId);}
async function duplizierePos(kalkId,posId){const{data}=await sb.from('kalk_positionen').select('*').eq('id',posId).single();if(!data)return;const{id,created_at,...rest}=data;await sb.from('kalk_positionen').insert({...rest,bezeichnung:rest.bezeichnung+' (Kopie)',user_id:me.id});pgKalkDetail(kalkId);}
function mKalkGlobalMarge(kalkId,aktMarge){oM(`${modalHeader('Globale Marge anpassen')}<div class="fg"><label>NEUE MARGE FÜR ALLE POSITIONEN (%)</label><input id="g-marge" type="number" value="${aktMarge}"></div><div style="background:var(--yellow-bg);border:1px solid var(--yellow);border-radius:var(--radius);padding:10px 14px;margin-bottom:16px;font-size:12px;color:var(--yellow);font-weight:600">⚠️ Überschreibt die Marge aller Positionen in dieser Kalkulation.</div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveGlobalMarge('${kalkId}')">Anwenden</button></div>`);}
async function saveGlobalMarge(kalkId){const marge=parseFloat(document.getElementById('g-marge').value)||20;const{data:pos}=await sb.from('kalk_positionen').select('id').eq('kalkulation_id',kalkId);if(pos)for(const p of pos)await sb.from('kalk_positionen').update({marge}).eq('id',p.id);await sb.from('kalkulationen').update({marge_gesamt:marge}).eq('id',kalkId);cM();pgKalkDetail(kalkId);}
async function kalkZuAngebot(kalkId){const[{data:k},{data:pos}]=await Promise.all([sb.from('kalkulationen').select('*').eq('id',kalkId).single(),sb.from('kalk_positionen').select('*').eq('kalkulation_id',kalkId).order('sort_order')]);if(!k||!pos||!pos.length){alert('Keine Positionen vorhanden!');return;}const positionen=pos.map(p=>{const mat=(p.menge||0)*(p.materialpreis||0)*(1+(p.verschnitt||0)/100);const arb=p.stunden>0?(p.stunden||0)*(p.stundensatz||0):(p.menge||0)*(p.arbeitspreis||0);const basis=mat+arb;const vk=basis*(1+(p.marge||20)/100);return{name:`${p.bezeichnung} (${p.menge} ${p.einheit})`,preis:vk};});const gesamt=positionen.reduce((s,p)=>s+p.preis,0);const nr='A-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('angebote').insert({nummer:nr,titel:k.name,kunde:k.kunde||'',datum:heute(),positionen:JSON.stringify(positionen),gesamt,status:'offen',user_id:me.id});if(error){alert('Fehler: '+error.message);return;}alert('Angebot erstellt! Nr. '+nr);go('angebote');}
sb.auth.getSession().then(({data:{session}})=>{if(session)sA(session.user);});
